    { label: 'Learning to breathe', steps: ['idle_south', 'idle_north', 'idle_east', 'idle_west'] },
  ];

  return phases.map(({ label, steps: phaseSteps }) => {
    const matched = steps.filter((s) => phaseSteps.includes(s.step));
    const allDone = matched.length > 0 && matched.every((s) => s.status === 'completed');
    const anyActive = matched.some((s) => s.status === 'pending') && matched.some((s) => s.status === 'completed');
    const anyPending = matched.some((s) => s.status === 'pending');

    if (allDone) return { label, status: 'done' as const };
    if (anyActive || (anyPending && matched.some((s) => s.status !== 'pending'))) return { label, status: 'active' as const };
    return { label, status: 'pending' as const };
  });
}

