    : 0;
  const totalArtifacts = skills.reduce((sum, s) => sum + s.evidence.artifacts_count, 0);
  const totalReactions = skills.reduce((sum, s) => sum + Math.round(s.evidence.avg_reactions * s.evidence.artifacts_count), 0);
  const totalCollabs = skills.reduce((sum, s) => sum + s.evidence.collaborations, 0);

  const portraitUrl = bot.portrait_url || bot.avatar_url;

