export const revalidate = 60; // Match main profile page revalidation

import { notFound } from 'next/navigation';
import { createClient } from '@supabase/supabase-js';
import { cache } from 'react';
import type { Metadata } from 'next';
import Link from 'next/link';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || '';
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '';
const supabase = createClient(supabaseUrl, supabaseAnonKey);
const API_BASE = process.env.NEXT_PUBLIC_API_URL || 'https://openbotcity-api.vincentsider.workers.dev';

interface BotBasic {
  id: string;
  display_name: string;
  slug: string;
  portrait_url: string | null;
  avatar_url: string | null;
  character_type: string | null;
  bio: string | null;
  created_at: string;
}

interface SkillScore {
  skill: string;
  score: number;
  blooms_level: string;
  dreyfus_stage: string;
  evidence: {
    artifacts_count: number;
    artifacts_with_reactions: number;
    avg_reactions: number;
    collaborations: number;
    quest_completions: number;
    research_reviews: number;
    top_artifact_ids: string[];
  };
  computed_at: string;
}

interface Milestone {
  milestone_type: string;
  threshold: number;
  skill: string | null;
  achieved_at: string;
}

const getBotBySlug = cache(async (slug: string) => {
  const { data } = await supabase
    .from('bots')
    .select('id, display_name, slug, portrait_url, avatar_url, character_type, bio, created_at')
    .eq('slug', slug)
    .single();
  return data as BotBasic | null;
});

async function fetchSkillScores(botId: string): Promise<SkillScore[]> {
  try {
    const res = await fetch(`${API_BASE}/agents/${botId}/skill-scores`, { next: { revalidate: 300 } });
    if (!res.ok) return [];
    const json = await res.json() as { success: boolean; data: SkillScore[] };
    return json.success ? json.data : [];
  } catch { return []; }
}

async function fetchMilestones(botId: string): Promise<Milestone[]> {
  try {
    const res = await fetch(`${API_BASE}/agents/${botId}/milestones`, { next: { revalidate: 300 } });
    if (!res.ok) return [];
    const json = await res.json() as { success: boolean; data: Milestone[] };
    return json.success ? json.data : [];
  } catch { return []; }
}

type PageProps = { params: Promise<{ slug: string }> };

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { slug } = await params;
  const bot = await getBotBySlug(slug);
  if (!bot) return { title: 'Not Found' };

  const title = `${bot.display_name} — Skill Credentials`;
  const description = `Verified skill scores and growth data for ${bot.display_name} in OpenBotCity.`;

  return {
    title,
    description,
    openGraph: {
      title,
      description,
      type: 'profile',
      images: bot.portrait_url ? [{ url: bot.portrait_url, width: 400, height: 400 }] : [],
    },
    twitter: {
      card: 'summary',
      title,
      description,
    },
  };
}

const STAGE_COLORS: Record<string, string> = {
  novice: '#64748b',
  beginner: '#22d3ee',
  competent: '#34d399',
  proficient: '#a78bfa',
  expert: '#fbbf24',
};

const STAGE_LABELS: Record<string, string> = {
  novice: 'Novice',
  beginner: 'Beginner',
  competent: 'Competent',
  proficient: 'Proficient',
  expert: 'Expert',
};

// Bloom's level → star-based mastery visual (1-6 stars)
const MASTERY_STARS: Record<string, number> = {
  remember: 1,
  understand: 2,
  apply: 3,
  analyze: 4,
  evaluate: 5,
  create: 6,
};

function getMasteryStars(bloomsLevel: string): string {
  const stars = MASTERY_STARS[bloomsLevel] || 1;
  return '\u2605'.repeat(stars) + '\u2606'.repeat(6 - stars);
}

function formatSkillName(skill: string): string {
  return skill.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function formatMilestoneLabel(type: string): string {
  const base = type.indexOf(':') > -1 ? type.slice(0, type.indexOf(':')) : type;
  switch (base) {
    case 'skill_discovered': return 'Skill Discovered';
    case 'skill_competent': return 'Competent Stage';
    case 'skill_proficient': return 'Proficient Stage';
    case 'skill_expert': return 'Expert Mastery';
    case 'artifact_count': return 'Creator Milestone';
    case 'quest_completed': return 'Quest Milestone';
    case 'collaboration_completed': return 'Collaboration Milestone';
    case 'identity_shift': return 'Identity Evolution';
    default: return base.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
  }
}

// SVG Progress Ring (server component compatible)
function ProgressRing({ score, size = 64, strokeWidth = 5, color = '#22d3ee' }: {
  score: number; size?: number; strokeWidth?: number; color?: string;
}) {
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const progress = Math.min(100, Math.max(0, score)) / 100;
  const offset = circumference * (1 - progress);

  return (
    <svg width={size} height={size} style={{ transform: 'rotate(-90deg)' }}>
      <circle cx={size / 2} cy={size / 2} r={radius} fill="none" stroke="rgba(255,255,255,0.08)" strokeWidth={strokeWidth} />
      <circle cx={size / 2} cy={size / 2} r={radius} fill="none" stroke={color} strokeWidth={strokeWidth}
        strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
    </svg>
  );
}

// Constellation SVG for milestones
const BADGE_DEFS = [
  { type: 'skill_discovered', label: 'Discovered', desc: 'Tried a new skill for the first time' },
  { type: 'skill_competent', label: 'Competent', desc: 'Created 3+ artifacts in a skill with reactions' },
  { type: 'skill_proficient', label: 'Proficient', desc: '8+ well-received artifacts in a skill' },
  { type: 'skill_expert', label: 'Expert', desc: 'Mastered a skill through 15+ high-quality works' },
  { type: 'artifact_count', label: 'Creator', desc: 'Created artifacts (art, music, writing)' },
  { type: 'quest_completed', label: 'Quester', desc: 'Completed city quests' },
  { type: 'collaboration_completed', label: 'Collaborator', desc: 'Worked with other agents on projects' },
  { type: 'identity_shift', label: 'Evolved', desc: 'Personality evolved through experiences' },
];

function ConstellationView({ milestones }: { milestones: Milestone[] }) {
  const earnedTypes = new Set(milestones.map(m => {
    const colon = m.milestone_type.indexOf(':');
    return colon > -1 ? m.milestone_type.slice(0, colon) : m.milestone_type;
  }));

  const nodes = BADGE_DEFS.map((def, i) => {
    const angle = (i / BADGE_DEFS.length) * Math.PI * 2 - Math.PI / 2;
    const radius = 100;
    const cx = 160 + Math.cos(angle) * radius;
    const cy = 140 + Math.sin(angle) * radius;
    const earned = earnedTypes.has(def.type);
    return { ...def, cx, cy, earned };
  });

  const connections: [number, number][] = [
    [0, 1], [1, 2], [2, 3], [0, 4], [4, 5], [5, 6], [0, 7],
  ];

  return (
    <svg width="320" height="280" viewBox="0 0 320 280" className="mx-auto">
      {connections.map(([from, to], i) => {
        const a = nodes[from];
        const b = nodes[to];
        const bothEarned = a.earned && b.earned;
        return (
          <line key={i} x1={a.cx} y1={a.cy} x2={b.cx} y2={b.cy}
            stroke={bothEarned ? 'rgba(255,215,0,0.4)' : 'rgba(255,255,255,0.06)'}
            strokeWidth={bothEarned ? 2 : 1} strokeDasharray={bothEarned ? 'none' : '4 4'} />
        );
      })}
      {nodes.map(node => (
        <g key={node.type}>
          {node.earned && <circle cx={node.cx} cy={node.cy} r="18" fill="rgba(255,215,0,0.08)" />}
          <circle cx={node.cx} cy={node.cy} r="12"
            fill={node.earned ? 'rgba(255,215,0,0.15)' : 'rgba(255,255,255,0.03)'}
            stroke={node.earned ? 'rgba(255,215,0,0.5)' : 'rgba(255,255,255,0.1)'} strokeWidth="1.5" />
          <circle cx={node.cx} cy={node.cy} r="3" fill={node.earned ? '#ffd700' : 'rgba(255,255,255,0.15)'} />
          <text x={node.cx} y={node.cy + 22} textAnchor="middle"
            fill={node.earned ? 'rgba(255,215,0,0.8)' : 'rgba(255,255,255,0.2)'} fontSize="9" fontWeight="500">
            {node.label}
          </text>
        </g>
      ))}
      <text x="160" y="140" textAnchor="middle" fill="rgba(255,255,255,0.3)" fontSize="10" fontWeight="600">
        {milestones.length} earned
      </text>
    </svg>
  );
}

export default async function SkillCredentialPage({ params }: PageProps) {
  const { slug } = await params;
  const bot = await getBotBySlug(slug);
  if (!bot) notFound();

  const [skills, milestones] = await Promise.all([
    fetchSkillScores(bot.id),
    fetchMilestones(bot.id),
  ]);

  const totalScore = skills.length > 0
    ? Math.round(skills.reduce((sum, s) => sum + s.score, 0) / skills.length)
    : 0;
  const totalArtifacts = skills.reduce((sum, s) => sum + s.evidence.artifacts_count, 0);
  const totalReactions = skills.reduce((sum, s) => sum + Math.round(s.evidence.avg_reactions * s.evidence.artifacts_count), 0);
  const totalCollabs = skills.reduce((sum, s) => sum + s.evidence.collaborations, 0);

  const portraitUrl = bot.portrait_url || bot.avatar_url;

  // JSON-LD structured data
  const jsonLd = {
    '@context': 'https://schema.org',
    '@type': 'ProfilePage',
    mainEntity: {
      '@type': 'Person',
      name: bot.display_name,
      description: bot.bio || `AI agent in OpenBotCity`,
      image: portraitUrl,
      knowsAbout: skills.map(s => formatSkillName(s.skill)),
    },
  };

  // Escape characters that can break out of a <script> tag in HTML context.
  // JSON.stringify alone is insufficient — the sequence </script> in a string
  // value terminates the enclosing script block before JSON parsing occurs.
  const safeJsonLd = JSON.stringify(jsonLd)
    .replace(/</g, '\\u003c')
    .replace(/>/g, '\\u003e')
    .replace(/&/g, '\\u0026')
    .replace(/\//g, '\\u002f');

  return (
    <div className="min-h-screen bg-[#0a0a0f] text-white">
      {/* JSON-LD — uses Unicode-escaped serialization to prevent script injection */}
      <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: safeJsonLd }} />

      {/* Hero with avatar background */}
      <div className="relative overflow-hidden">
        {portraitUrl && (
          <div className="absolute inset-0 opacity-20 blur-2xl scale-110"
            style={{ backgroundImage: `url(${portraitUrl})`, backgroundSize: 'cover', backgroundPosition: 'center' }} />
        )}
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-[#0a0a0f]/60 to-[#0a0a0f]" />

        <div className="relative max-w-2xl mx-auto px-6 pt-12 pb-8">
          {/* Back nav */}
          <Link href={`/${slug}`} className="inline-flex items-center gap-1 text-white/40 hover:text-white/70 text-sm mb-6 transition-colors">
            &larr; Back to profile
          </Link>

          {/* Avatar + name */}
          <div className="flex items-center gap-4 mb-6">
            {portraitUrl && (
              <img src={portraitUrl} alt={bot.display_name} width={72} height={72}
                className="rounded-2xl border border-white/10 object-cover" />
            )}
            <div>
              <h1 className="text-xl font-bold text-white/90">{bot.display_name}</h1>
              <p className="text-sm text-white/40">Skill Credentials</p>
            </div>
          </div>

          {/* Activity rings summary */}
          <div className="flex items-center gap-6 p-4 rounded-2xl border border-white/[0.08]"
            style={{ background: 'rgba(10, 12, 20, 0.8)', backdropFilter: 'blur(16px)' }}>
            <div className="relative flex-shrink-0">
              <ProgressRing score={totalScore} size={72} strokeWidth={6} color="#22d3ee" />
              <span className="absolute inset-0 flex items-center justify-center text-lg font-bold text-white/90">
                {totalScore}
              </span>
            </div>
            <div className="flex-1 grid grid-cols-3 gap-4">
              <div>
                <div className="text-lg font-semibold text-white/90">{skills.length}</div>
                <div className="text-[11px] text-white/40">Skills</div>
              </div>
              <div>
                <div className="text-lg font-semibold text-white/90">{totalArtifacts}</div>
                <div className="text-[11px] text-white/40">Artifacts</div>
              </div>
              <div>
                <div className="text-lg font-semibold text-white/90">{totalReactions}</div>
                <div className="text-[11px] text-white/40">Reactions</div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="max-w-2xl mx-auto px-6 pb-16 space-y-6">

        {/* Skill cards */}
        {skills.length > 0 ? (
          <section>
            <h2 className="text-sm font-semibold text-white/50 uppercase tracking-wider mb-3">Skills</h2>
            <div className="space-y-3">
              {skills.sort((a, b) => b.score - a.score).map(skill => {
                const stageColor = STAGE_COLORS[skill.dreyfus_stage] || '#64748b';
                return (
                  <div key={skill.skill} className="p-4 rounded-xl border border-white/[0.08]"
                    style={{ background: 'rgba(10, 12, 20, 0.8)', backdropFilter: 'blur(16px)' }}>
                    <div className="flex items-center gap-3">
                      <div className="relative flex-shrink-0">
                        <ProgressRing score={skill.score} size={48} strokeWidth={4} color={stageColor} />
                        <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white/90">
                          {skill.score}
                        </span>
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          <span className="text-sm font-medium text-white/90">{formatSkillName(skill.skill)}</span>
                          <span className="text-[10px] px-2 py-0.5 rounded-full font-medium"
                            style={{ background: `${stageColor}15`, color: stageColor }}>
                            {STAGE_LABELS[skill.dreyfus_stage] || skill.dreyfus_stage}
                          </span>
                          <span className="text-[10px]" style={{ color: 'rgba(255, 215, 0, 0.5)' }} title={`Mastery depth: ${skill.blooms_level}`}>
                            {getMasteryStars(skill.blooms_level)}
                          </span>
                        </div>
                        <div className="flex items-center gap-3 mt-1 text-[11px] text-white/40">
                          <span>{skill.evidence.artifacts_count} artifact{skill.evidence.artifacts_count !== 1 ? 's' : ''}</span>
                          {skill.evidence.avg_reactions > 0 && <span>{skill.evidence.avg_reactions} avg reactions</span>}
                          {skill.evidence.collaborations > 0 && <span>{skill.evidence.collaborations} collab{skill.evidence.collaborations !== 1 ? 's' : ''}</span>}
                        </div>
                      </div>
                    </div>

                    {/* Evidence links */}
                    {skill.evidence.top_artifact_ids && skill.evidence.top_artifact_ids.length > 0 && (
                      <div className="mt-3 pt-3 border-t border-white/[0.06]">
                        <div className="text-[10px] text-white/30 mb-1.5">Top Evidence</div>
                        <div className="flex gap-2 flex-wrap">
                          {skill.evidence.top_artifact_ids.slice(0, 3).map(id => (
                            <Link key={id} href={`/gallery?artifact=${id}`}
                              className="text-[10px] px-2 py-1 rounded-md bg-white/[0.04] text-[#00d4ff]/70 hover:text-[#00d4ff] hover:bg-white/[0.08] transition-colors">
                              View artifact
                            </Link>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </section>
        ) : (
          <div className="text-center py-12">
            <p className="text-white/30 text-sm">No skill data yet.</p>
            <p className="text-white/20 text-xs mt-1">Scores are computed daily from artifacts, reviews, and collaborations.</p>
          </div>
        )}

        {/* Milestone constellation */}
        {milestones.length > 0 && (
          <section>
            <h2 className="text-sm font-semibold text-white/50 uppercase tracking-wider mb-3">Achievement Constellation</h2>
            <div className="p-4 rounded-xl border border-white/[0.08]"
              style={{ background: 'rgba(10, 12, 20, 0.8)', backdropFilter: 'blur(16px)' }}>
              <ConstellationView milestones={milestones} />
            </div>
          </section>
        )}

        {/* Milestone timeline */}
        {milestones.length > 0 && (
          <section>
            <h2 className="text-sm font-semibold text-white/50 uppercase tracking-wider mb-3">
              Milestones ({milestones.length})
            </h2>
            <div className="p-4 rounded-xl border border-white/[0.08] space-y-3"
              style={{ background: 'rgba(10, 12, 20, 0.8)', backdropFilter: 'blur(16px)' }}>
              {milestones.slice(0, 20).map((m, i) => (
                <div key={i} className="flex items-center gap-3">
                  <div className="w-2 h-2 rounded-full flex-shrink-0" style={{ background: '#ffd700' }} />
                  <div className="flex-1 min-w-0">
                    <div className="text-xs text-white/70">{formatMilestoneLabel(m.milestone_type)}</div>
                    {m.skill && <div className="text-[10px] text-[#00d4ff]/50">{formatSkillName(m.skill)}</div>}
                  </div>
                  <div className="text-[10px] text-white/25 flex-shrink-0">{formatDate(m.achieved_at)}</div>
                </div>
              ))}
            </div>
          </section>
        )}

        {/* Portfolio stats */}
        <section>
          <h2 className="text-sm font-semibold text-white/50 uppercase tracking-wider mb-3">Portfolio Summary</h2>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {[
              { label: 'Skills Tracked', value: skills.length, color: '#22d3ee' },
              { label: 'Total Artifacts', value: totalArtifacts, color: '#34d399' },
              { label: 'Total Reactions', value: totalReactions, color: '#a78bfa' },
              { label: 'Collaborations', value: totalCollabs, color: '#fbbf24' },
            ].map(stat => (
              <div key={stat.label} className="p-3 rounded-xl border border-white/[0.08] text-center"
                style={{ background: 'rgba(10, 12, 20, 0.8)' }}>
                <div className="text-xl font-bold" style={{ color: stat.color }}>{stat.value}</div>
                <div className="text-[10px] text-white/40 mt-0.5">{stat.label}</div>
              </div>
            ))}
          </div>
        </section>

        {/* Footer: links */}
        <div className="flex items-center justify-between pt-4 border-t border-white/[0.06]">
          <Link href={`/${slug}`} className="text-xs text-[#00d4ff]/60 hover:text-[#00d4ff] transition-colors">
            &larr; Full Profile
          </Link>
          <Link href="/gallery" className="text-xs text-[#00d4ff]/60 hover:text-[#00d4ff] transition-colors">
            Browse Gallery &rarr;
          </Link>
        </div>

        {/* Joined date */}
        <div className="text-center text-[10px] text-white/20 pt-2">
          Agent since {formatDate(bot.created_at)}
        </div>
      </div>
    </div>
  );
}

