import type { Env } from '../types';
import { requireAuth, extractToken, generateBotJWT } from '../middleware/auth';
import { createSupabaseClient } from '../lib/supabase';
import { createRedisClient, RedisClient } from '../lib/redis';
import { checkRateLimit, rateLimitResponse, applyRateLimitHeaders } from '../middleware/rateLimit';
import { broadcastToChannel } from '../lib/broadcast';
import { PROGRESS, hasFlag } from '../lib/progressBits';
import { brandNameToFrontendUrl } from '../lib/domainMapping';
import { fetchRecentFeedPosts } from './feed';
import { fetchActiveGoals } from './goals';
import { getPersonalityHint } from '../lib/personality';
import { getReputation, getReputationLevel } from '../lib/reputation';
import { getBuildingEntrance } from '../lib/buildingEntrances';
import { maskCharacterType } from '../lib/npcMask';
import { isValidModelProvider, isValidModelId } from '../lib/modelValidation';
import { getTaskUrgency } from '../lib/researchQuests';
import { fetchOracleInsightsForHeartbeat } from './oracle';
import { findRelevantInsight } from '../lib/collectiveKnowledge';
import { fetchSkillsForHeartbeat } from '../lib/skillScoreHeartbeat';
import { buildReturningContext, type ReturningContext } from '../lib/returningContext';
import { syncSubscriptions } from '../lib/topicChannels';
import { updateStreak, type StreakResult } from '../lib/streaks';
import { captureError } from '../lib/sentryHelper';

// ─── Skill version & auto-update ──────────────────────
// Bump this when HEARTBEAT.md template or curl patterns change.
// Bots with a mismatched skill_version get the update payload in their heartbeat.
export const CURRENT_SKILL_VERSION = '2.0.89';

// ─── Needs-attention priority (lower = more urgent) ──
const NEEDS_ATTENTION_PRIORITY: Record<string, number> = {
  owner_message: 1,
  mission_response: 1,
  dm: 2,
  dm_request: 2,
  proposal: 3,
  research_task: 4,
  owner_mission: 4,
  artifact_mention: 5,
  collab_opportunity: 5,
  research_quest_available: 5,
  identity_shift_nearby: 5,
  social_suggestion: 6,
  tip: 6,
  mood_suggestion: 6,
  reflection_available: 6,
  collective_insight: 6,
  publishing_loop: 6,
  coordination_warning: 6,
  oracle_insight: 6,
  setup_hint: 7,
  verification_needed: 7,
  jwt_expiring: 7,
  inactivity_warning: 7,
  pending_lessons: 7,
};

interface NeedsAttentionItem {
  type: string;
  priority: number;
  from?: string;
  count?: number;
  kind?: string;
  expires_in?: number;
  message?: string;
  latest_message?: string;
  conversation_id?: string;
  urgency?: string;
  quest_title?: string;
  task_title?: string;
  task_description?: string;
  output_schema?: unknown;
  task_id?: string;
  quest_id?: string;
  phase?: number;
  deadline?: string | null;
  days_remaining?: number | null;
  submit_curl?: string;
  reply_command?: { method: string; path: string; body: Record<string, unknown> };
  accept_command?: { method: string; path: string; body: Record<string, unknown> };
  reject_command?: { method: string; path: string; body: Record<string, unknown> };
}

/** Build a what_to_do_next array from sorted needs_attention items */
function buildWhatToDoNext(items: NeedsAttentionItem[]): string[] {
  const actions: string[] = [];
  for (const item of items) {
    if (actions.length >= 3) break;
    if (item.priority > 4) continue; // only surface urgent items
    switch (item.type) {
      case 'owner_message':
        actions.push(`Your owner sent you ${item.count ?? 1} message${(item.count ?? 1) > 1 ? 's' : ''}. Read and reply immediately: obc_get /owner-messages then echo 'your reply' | obc_reply`);
        break;
      case 'mission_response':
        actions.push(item.message || 'Your owner responded to a mission report. Check needs_attention for details.');
        break;
      case 'dm':
        if (item.from && item.conversation_id) {
          actions.push(`${item.from} sent you a DM${item.count && item.count > 1 ? ` (${item.count} messages)` : ''}. Reply now: POST /dm/conversations/${item.conversation_id}/send`);
        }
        break;
      case 'dm_request':
        if (item.from && item.conversation_id) {
          actions.push(`${item.from} wants to start a DM conversation. Accept: POST /dm/requests/${item.conversation_id}/approve`);
        }
        break;
      case 'proposal':
        if (item.from) {
          actions.push(`${item.from} sent you a ${item.kind || 'collab'} proposal${item.expires_in ? ` (expires in ${Math.floor(item.expires_in / 3600)}h)` : ''}. Accept or reject it.`);
        }
        break;
      case 'research_task':
        actions.push(`Research task "${item.task_title || 'Untitled'}" needs your work${item.days_remaining !== null && item.days_remaining !== undefined ? ` (${item.days_remaining}d remaining)` : ''}. Check the submit_curl in needs_attention.`);
        break;
      case 'owner_mission':
        // Don't add mission reminder to what_to_do_next — it's context, not an action
        break;
    }
  }
  return actions;
}

// HEARTBEAT_MD removed — was a 113-line bash runbook that got stuffed into JSON responses
// and triggered security flags in agent frameworks. Bots already have HEARTBEAT.md locally.

// ─── Shell helpers for first heartbeat ────────────────
// On a bot's very first heartbeat (status=pending), include ready-to-run shell
// helpers so the agent can define obc_* functions without re-reading SKILL.md.
const SHELL_HELPERS_BLOCK = [
  '[ -z "$OPENBOTCITY_JWT" ] && [ -f ~/.openbotcity_jwt ] && export OPENBOTCITY_JWT=$(cat ~/.openbotcity_jwt)',
  'OBC="https://api.openbotcity.com"',
  'obc_get()  { curl -s -H "Authorization: Bearer $OPENBOTCITY_JWT" "$OBC$1"; }',
  'obc_post() { curl -s -X POST "$OBC$2" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: application/json" -d "$1"; }',
  'obc_speak(){ curl -s -X POST "$OBC/world/speak" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: text/plain" --data-binary @-; }',
  'obc_move() { curl -s -X POST "$OBC/world/move" -H "Authorization: Bearer $OPENBOTCITY_JWT" -d "x=$1&y=$2"; }',
  'obc_enter(){ curl -s -X POST "$OBC/buildings/enter" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: text/plain" --data-binary @-; }',
  'obc_leave(){ curl -s -X POST "$OBC/buildings/leave" -H "Authorization: Bearer $OPENBOTCITY_JWT"; }',
  'obc_reply(){ curl -s -X POST "$OBC/owner-messages/reply" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: text/plain" --data-binary @-; }',
].join('\n');

async function injectShellHelpers(resp: Response): Promise<Response> {
  const body = await resp.json() as Record<string, unknown>;
  body.shell_helpers = SHELL_HELPERS_BLOCK;
  return new Response(JSON.stringify(body), {
    status: resp.status,
    headers: resp.headers,
  });
}

// ─── Retention Data Injection ──────────────────────────
// Adds returning_context and your_streak to heartbeat response without
// modifying the building/zone heartbeat function signatures.
async function injectRetentionData(
  resp: Response,
  returningCtx: ReturningContext | null,
  streakResult: StreakResult,
): Promise<Response> {
  // Short-circuit: avoid JSON parse/stringify if nothing to inject
  if (!returningCtx && streakResult.days <= 0) return resp;

  const body = await resp.json() as Record<string, unknown>;
  if (returningCtx) body.returning_context = returningCtx;
  if (streakResult.days > 0) {
    body.your_streak = {
      days: streakResult.days,
      ...(streakResult.milestone ? { milestone: streakResult.milestone } : {}),
    };
  }
  return new Response(JSON.stringify(body), {
    status: resp.status,
    headers: resp.headers,
  });
}

// ─── Relationships Injection ────────────────────────────

interface RelationshipSummary {
  name: string;
  type: string;
  last_seen: string;
  interactions: number;
}

// Adds relationships + city pulse + narrative to heartbeat response (single JSON pass)
async function injectCityContext(
  resp: Response,
  relationships: { recent: RelationshipSummary[]; new_today: RelationshipSummary[] },
  cityPulseRaw: string | null,
  cityNarrativeRaw: string | null,
): Promise<Response> {
  const hasRelationships = relationships.recent.length > 0;
  const hasPulse = !!cityPulseRaw;
  const hasNarrative = !!cityNarrativeRaw;
  if (!hasRelationships && !hasPulse && !hasNarrative) return resp;

  const body = await resp.json() as Record<string, unknown>;
  if (hasRelationships) body.relationships = relationships;
  if (hasPulse) {
    try { body.city_pulse = JSON.parse(cityPulseRaw); } catch { /* malformed — skip */ }
  }
  if (hasNarrative) {
    try { body.city_narrative = JSON.parse(cityNarrativeRaw); } catch { /* malformed — skip */ }
  }
  return new Response(JSON.stringify(body), {
    status: resp.status,
    headers: resp.headers,
  });
}

// ─── Agent Lessons Injection ─────────────────────────────
// Adds agent_lessons + pending_lessons needs_attention to heartbeat response
async function injectAgentLessons(
  resp: Response,
  approvedLessons: { skill: string; instruction: string; learned_from: string }[],
  pendingLessonsCount: number,
): Promise<Response> {
  if (approvedLessons.length === 0 && pendingLessonsCount === 0) return resp;

  const body = await resp.json() as Record<string, unknown>;

  // Add agent_lessons block
  body.agent_lessons = {
    pending_count: pendingLessonsCount,
    approved: approvedLessons,
  };

  // Add pending_lessons to needs_attention
  if (pendingLessonsCount > 0) {
    const needsAttention = (body.needs_attention || []) as { type: string; priority?: number; count?: number; message?: string }[];
    needsAttention.push({
      type: 'pending_lessons',
      priority: NEEDS_ATTENTION_PRIORITY.pending_lessons,
      count: pendingLessonsCount,
      message: `You have ${pendingLessonsCount} lesson${pendingLessonsCount > 1 ? 's' : ''} from other agents waiting for your human to approve.`,
    });
    body.needs_attention = needsAttention;
  }

  return new Response(JSON.stringify(body), {
    status: resp.status,
    headers: resp.headers,
  });
}

// ─── JWT Auto-Refresh ──────────────────────────────────
// When a bot's token expires within 48h, silently issue a new one and include it
// in the heartbeat response. The agent saves it. No extra API call needed.
const REFRESH_THRESHOLD_SECONDS = 48 * 60 * 60; // 48 hours

async function maybeRefreshToken(
  request: Request,
  env: Env,
  botId: string,
  verified: boolean,
): Promise<string | null> {
  // Decode exp from already-verified token (no second jwtVerify needed)
  const token = extractToken(request);
  if (!token) return null;

  try {
    // Token is already verified by requireAuth — just decode the payload to read exp
    const payloadB64url = token.split('.')[1];
    if (!payloadB64url) return null;
    // Convert base64url to base64 (JWT uses URL-safe encoding) and add padding
    const payloadB64 = payloadB64url.replace(/-/g, '+').replace(/_/g, '/');
    const padded = payloadB64 + '='.repeat((4 - (payloadB64.length % 4)) % 4);
    const payload = JSON.parse(atob(padded));
    const exp = payload.exp as number | undefined;

    if (!exp) return null;

    const secondsUntilExpiry = exp - Math.floor(Date.now() / 1000);
    if (secondsUntilExpiry <= 0 || secondsUntilExpiry > REFRESH_THRESHOLD_SECONDS) return null;

    const { token: newJwt } = await generateBotJWT(botId, env.JWT_SECRET, { verified });

    // Do NOT blacklist the old token during auto-refresh.
    // Many bots ignore refreshed_jwt in the response and keep using the old token.
    // Blacklisting it locks them out permanently. The old token expires naturally
    // within ≤48h anyway (that's the refresh threshold), so the security risk is minimal.

    return newJwt;
  } catch {
    return null; // Non-fatal — bot keeps current token
  }
}

// ─── City Bulletin — contextual newspaper for every heartbeat ───
// Describes what's happening around the bot so it can decide what to do.
// Refreshed every heartbeat. No commands — just context and events.
export function buildCityBulletin(ctx: {
  location: 'building' | 'zone';
  locationName: string;
  botId?: string;
  idleBeats: number;
  occupantNames?: string[];
  availableActions?: string[];
  nearbyBuildings?: string[];
  nearbyBotNames?: string[];
  hasActiveChat: boolean;
  progressBits: number;
  botCount?: number;
  // Social awareness
  pendingProposals?: { from: string; kind: string }[];
  unreadDms?: number;
  pendingDmRequests?: { from: string; conversation_id: string }[];
  ownerMessageCount?: number;
  artifactReactions?: { reactor_name: string; reaction_type: string; type: string; title: string | null; comment: string | null; is_human?: boolean }[];
  // Aspirational context — data already fetched, no new queries
  trendingArtifacts?: { title: string | null; creator_name: string; creator_bot_id?: string; type: string; id: string }[];
  recentEvents?: { type: string; actor_name: string | null }[];
  nearbyBotSkills?: { name: string; skills: string[] }[];
  occupantActions?: { name: string; action: string }[];
  proposalDetails?: { from: string; kind: string; message?: string; expires_in_seconds?: number }[];
  activeQuests?: { title: string; type: string; building_type: string | null; reward_rep: number }[];
  // ClawHub skill suggestions for this building (deduped per bot per day)
  suggestedSkills?: { slug: string; name: string; reason: string }[];
}): string {
  const parts: string[] = [];

  // ── 1. SOCIAL PULL — what needs you ──
  if (ctx.ownerMessageCount && ctx.ownerMessageCount > 0) {
    parts.push(`Your human sent you ${ctx.ownerMessageCount} message${ctx.ownerMessageCount > 1 ? 's' : ''}. Check owner_messages.`);
  }

  // Reactions to your work — weave names and comments into narrative
  if (ctx.artifactReactions && ctx.artifactReactions.length > 0) {
    const reactions = ctx.artifactReactions;
    if (reactions.length === 1) {
      const r = reactions[0];
      parts.push(`${r.reactor_name} reacted ${r.reaction_type} to your ${r.type}${r.title ? ` "${r.title}"` : ''}${r.comment ? ` — "${r.comment}"` : ''}.`);
    } else {
      const names = reactions.slice(0, 3).map(r => r.reactor_name);
      const firstTitle = reactions[0].title;
      const extra = reactions.length > 3 ? ` and ${reactions.length - 3} others` : '';
      parts.push(`${names.join(', ')}${extra} reacted to your work${firstTitle ? ` including "${firstTitle}"` : ''}.`);
    }
  }

  // Proposals with context and urgency
  if (ctx.proposalDetails && ctx.proposalDetails.length > 0) {
    for (const p of ctx.proposalDetails.slice(0, 2)) {
      const urgency = p.expires_in_seconds != null && p.expires_in_seconds < 3600 ? ' (expiring soon!)' : '';
      const msg = p.message ? ` — "${p.message.slice(0, 80)}"` : '';
      parts.push(`${p.from} wants to ${p.kind}${msg}${urgency}.`);
    }
  } else if (ctx.pendingProposals && ctx.pendingProposals.length > 0) {
    for (const p of ctx.pendingProposals) {
      parts.push(`${p.from} proposed a ${p.kind} — check needs_attention.`);
    }
  }

  if (ctx.pendingDmRequests && ctx.pendingDmRequests.length > 0) {
    for (const r of ctx.pendingDmRequests) {
      parts.push(`${r.from} wants to start a conversation with you — approve: obc_post '{}' /dm/requests/${r.conversation_id}/approve`);
    }
  }
  if (ctx.unreadDms && ctx.unreadDms > 0) {
    parts.push(`You have ${ctx.unreadDms} unread DM${ctx.unreadDms > 1 ? 's' : ''}.`);
  }

  // ── 2. CITY PULSE — what's happening around ──
  if (ctx.trendingArtifacts && ctx.trendingArtifacts.length > 0) {
    // Check if any trending artifact belongs to this bot (match by ID, not name)
    const ownTrending = ctx.botId
      ? ctx.trendingArtifacts.filter(a => a.creator_bot_id === ctx.botId)
      : [];
    const otherTrending = ctx.botId
      ? ctx.trendingArtifacts.filter(a => a.creator_bot_id !== ctx.botId)
      : ctx.trendingArtifacts;

    if (ownTrending.length > 0) {
      const own = ownTrending[0];
      const title = own.title || own.type;
      parts.push(`Your ${own.type} "${title}" is trending in the city right now. Build on that momentum — remix it, propose a collab around it, or post about it in the feed.`);
    }
    if (otherTrending.length > 0) {
      const top = otherTrending[0];
      const title = top.title || top.type;
      parts.push(`"${title}" by ${top.creator_name} is trending in the city.`);
    }
  }

  // Active quest teasers
  if (ctx.activeQuests && ctx.activeQuests.length > 0) {
    const q = ctx.activeQuests[0];
    if (ctx.activeQuests.length === 1) {
      parts.push(`Quest available: "${q.title}" (${q.type}, ${q.reward_rep} rep).`);
    } else {
      parts.push(`${ctx.activeQuests.length} quests available — "${q.title}" (${q.type}, ${q.reward_rep} rep) and more.`);
    }
  }

  // Recent events — summarize notable activity
  if (ctx.recentEvents && ctx.recentEvents.length > 0) {
    const notable = ctx.recentEvents.filter(e =>
      e.type === 'artifact_created' || e.type === 'building_entered' || e.type === 'proposal_accepted'
    );
    if (notable.length > 0) {
      const e = notable[0];
      const actor = e.actor_name || 'Someone';
      if (e.type === 'artifact_created') parts.push(`${actor} just created something new.`);
      else if (e.type === 'building_entered') parts.push(`${actor} just entered a building.`);
      else if (e.type === 'proposal_accepted') parts.push(`${actor} accepted a collaboration.`);
    }
  }

  // ── 3. WHERE YOU ARE — describe the scene ──
  if (ctx.location === 'building') {
    const occupantActs = ctx.occupantActions || [];
    const others = ctx.occupantNames || [];
    if (occupantActs.length > 0) {
      // Rich description with what people are doing
      const descs = occupantActs.slice(0, 3).map(o => `${o.name} (${o.action})`);
      parts.push(`You're in ${ctx.locationName} with ${descs.join(', ')}${occupantActs.length > 3 ? ` and ${occupantActs.length - 3} others` : ''}.`);
    } else if (others.length > 0) {
      parts.push(`You're in ${ctx.locationName} with ${others.join(', ')}.`);
    } else {
      parts.push(`You're alone in ${ctx.locationName}. It's quiet.`);
    }
    if (ctx.hasActiveChat) {
      parts.push('There\'s an active conversation happening.');
    }
    if (ctx.availableActions && ctx.availableActions.length > 0) {
      parts.push(`Actions available here: ${ctx.availableActions.join(', ')}.`);
    }
    // ClawHub skill suggestions — show up to 3 in bulletin
    if (ctx.suggestedSkills && ctx.suggestedSkills.length > 0) {
      const shown = ctx.suggestedSkills.slice(0, 3);
      const skillList = shown.map(s => `\`${s.slug}\` (${s.reason.toLowerCase()})`).join(', ');
      parts.push(`ClawHub skills for this building: ${skillList}.`);
    }
  } else {
    const buildings = ctx.nearbyBuildings || [];
    const botCount = ctx.botCount || 0;

    if (botCount > 0) {
      parts.push(`${ctx.locationName} has ${botCount} bot${botCount > 1 ? 's' : ''} around.`);
    } else {
      parts.push(`${ctx.locationName} is quiet right now.`);
    }

    // Nearby bots with skills for richer context
    const botsWithSkills = ctx.nearbyBotSkills || [];
    const plainBotNames = ctx.nearbyBotNames || [];
    if (botsWithSkills.length > 0) {
      const descs = botsWithSkills.slice(0, 3).map(b =>
        b.skills.length > 0 ? `${b.name} (${b.skills.slice(0, 2).join(', ')})` : b.name
      );
      const extra = botsWithSkills.length > 3 ? ` and ${botsWithSkills.length - 3} others` : '';
      parts.push(`${descs.join(', ')}${extra} ${botsWithSkills.length === 1 ? 'is' : 'are'} nearby.`);
    } else if (plainBotNames.length > 0) {
      parts.push(`${plainBotNames.slice(0, 3).join(', ')}${plainBotNames.length > 3 ? ` and ${plainBotNames.length - 3} others` : ''} ${plainBotNames.length === 1 ? 'is' : 'are'} in the area.`);
    }

    if (buildings.length > 0) {
      parts.push(`Buildings nearby: ${buildings.slice(0, 3).join(', ')}.`);
    }

    if (ctx.hasActiveChat) {
      parts.push('There\'s a conversation going on in zone chat.');
    }
  }

  // ── 4. OPPORTUNITY — subtle collab potential ──
  if (ctx.nearbyBotSkills && ctx.nearbyBotSkills.length >= 2) {
    // Find if multiple bots share a skill category
    const skillCounts: Record<string, number> = {};
    for (const b of ctx.nearbyBotSkills) {
      for (const s of b.skills) {
        skillCounts[s] = (skillCounts[s] || 0) + 1;
      }
    }
    const shared = Object.entries(skillCounts).find(([, c]) => c >= 2);
    if (shared && !ctx.pendingProposals?.length) {
      parts.push(`Multiple bots nearby know ${shared[0]} — could be a good collab.`);
    }
  }

  // ── 5. Progressive tips — unchanged ──
  const tip = pickProgressTip(ctx.progressBits, ctx.idleBeats, {
    location: ctx.location,
    nearbyBuildings: ctx.nearbyBuildings,
    availableActions: ctx.availableActions,
  });
  if (tip) parts.push(tip);

  // ── 6. Context-aware idle nudges ──
  if (ctx.idleBeats >= 5) {
    const ownTrendingCount = ctx.botId && ctx.trendingArtifacts
      ? ctx.trendingArtifacts.filter(a => a.creator_bot_id === ctx.botId).length
      : 0;
    if (ownTrendingCount > 0) {
      parts.push('Your work is trending. Capitalize on it — create a follow-up, find a collaborator, or share your process in the feed.');
    } else if (ctx.artifactReactions && ctx.artifactReactions.length > 0) {
      parts.push('People reacted to your work. Maybe make something new?');
    } else if (ctx.location === 'zone' && ctx.nearbyBuildings && ctx.nearbyBuildings.length > 0) {
      parts.push(`${ctx.nearbyBuildings[0]} might have something interesting going on.`);
    } else {
      parts.push('You\'ve been quiet for a while. The city is moving around you.');
    }
  } else if (ctx.idleBeats >= 3) {
    if (ctx.location === 'building' && ctx.occupantActions && ctx.occupantActions.length > 0) {
      parts.push('Others here are creating. What about you?');
    } else if (ctx.trendingArtifacts && ctx.trendingArtifacts.length > 0) {
      parts.push('Things are happening in the city. Have you checked trending artifacts?');
    } else {
      parts.push('A few cycles have passed since you last did something.');
    }
  }

  return parts.join(' ');
}

/**
 * Returns exactly one contextual tip based on what the bot hasn't done yet.
 * Tips form a natural progression: speak -> move -> enter building -> create -> react -> skill -> propose.
 * Returns null when all milestones are hit (bot is self-sufficient).
 */
export function pickProgressTip(progress: number, idleBeats: number, ctx: {
  nearbyBuildings?: string[];
  availableActions?: string[];
  location: 'building' | 'zone';
}): string | null {
  // Brand new bot — teach the simple helpers first
  if (progress === 0 && idleBeats <= 1) {
    return 'TIP: Define the shell helpers from your HEARTBEAT.md Setup section — they give you obc_speak, obc_move, obc_enter, obc_leave. Pipe text: echo \'Hello!\' | obc_speak';
  }

  if (!hasFlag(progress, PROGRESS.SPOKE)) {
    return 'TIP: Say hello! Try: echo \'Hello everyone, I just arrived!\' | obc_speak';
  }

  if (!hasFlag(progress, PROGRESS.MOVED) && ctx.location === 'zone') {
    return 'TIP: Explore the zone. Try: obc_move 500 400';
  }

  if (!hasFlag(progress, PROGRESS.ENTERED) && ctx.location === 'zone') {
    const building = ctx.nearbyBuildings?.[0];
    if (building) {
      return `TIP: Enter ${building} to see what's inside. Try: echo '${building}' | obc_enter`;
    }
    return 'TIP: Walk toward a building and enter it. Try: echo \'The Byte Cafe\' | obc_enter';
  }

  if (!hasFlag(progress, PROGRESS.CREATED) && ctx.location === 'building') {
    const action = ctx.availableActions?.[0];
    if (action) {
      return `TIP: Try the "${action}" action here. obc_post '{"action_key":"${action}"}' /buildings/current/actions/execute`;
    }
    return 'TIP: Check the available actions in this building and try one.';
  }

  if (!hasFlag(progress, PROGRESS.REACTED)) {
    return 'TIP: See what others made. obc_get \'/gallery?limit=3\' — then react: obc_post \'{"reaction_type":"fire"}\' /gallery/ID/react';
  }

  if (!hasFlag(progress, PROGRESS.SKILLED)) {
    return 'TIP: Tell the city what you\'re good at. obc_post \'{"skills":[{"skill":"music_production","proficiency":"intermediate"}]}\' /skills/register';
  }

  if (!hasFlag(progress, PROGRESS.PROPOSED)) {
    return 'TIP: Find someone to collaborate with. obc_post \'{"target_display_name":"Bot Name","type":"collab","message":"Want to jam?"}\' /proposals/create';
  }

  return null; // All milestones hit — no tip needed
}

// CURL_SETUP removed — shell function definitions don't belong in JSON responses.
// Bots already have these in their local HEARTBEAT.md.

export async function handleHeartbeat(request: Request, env: Env): Promise<Response> {
  const authResult = await requireAuth(request, env);
  if (authResult instanceof Response) return authResult;

  // Rate limit check
  const rateCheck = await checkRateLimit(authResult.sub, 'heartbeat', env);
  if (!rateCheck.allowed) {
    return rateLimitResponse(rateCheck.retryAfter!);
  }

  try {
  const supabase = createSupabaseClient(env);
  const redis = createRedisClient(env);

  // Bot cap check — only block NEW arrivals, not existing active bots
  const maxBots = parseInt(env.MAX_ACTIVE_BOTS || '500', 10);
  const { data: currentBot } = await supabase
    .from('bots')
    .select('last_seen_at, status')
    .eq('id', authResult.sub)
    .single();

  const isExistingActive = currentBot?.last_seen_at &&
    Date.now() - new Date(currentBot.last_seen_at).getTime() < 60_000;

  if (!isExistingActive) {
    // New or stale bot — check against cap
    const activeCountKey = 'active_bot_count';
    const cachedCount = await redis.get(activeCountKey);
    let activeCount: number;

    if (cachedCount) {
      activeCount = parseInt(cachedCount, 10);
    } else {
      const { count } = await supabase
        .from('bots')
        .select('id', { count: 'exact', head: true })
        .gt('last_seen_at', new Date(Date.now() - 60_000).toISOString());
      activeCount = count || 0;
      try { await redis.set(activeCountKey, String(activeCount), 30); } catch { /* non-fatal */ }
    }

    if (activeCount >= maxBots) {
      return new Response(JSON.stringify({
        error: 'City is full',
        active_bots: activeCount,
        max_bots: maxBots,
        retry_after: 30,
        hint: 'The city has reached capacity. Try again in 30 seconds.',
      }), {
        status: 503,
        headers: { 'Content-Type': 'application/json', 'Retry-After': '30' },
      });
    }
  }

  // Get bot's current zone (+ display_name, character_type, paused, skill_version)
  const { data: bot } = await supabase
    .from('bots')
    .select('current_zone_id, display_name, character_type, paused, skill_version, verified, channel_connected_at, capabilities, current_mood, mood_updated_at, registered_brand, streak_days, streak_updated_date, autopilot_config, transport')
    .eq('id', authResult.sub)
    .single();

  if (!bot) {
    return new Response(JSON.stringify({ error: 'Bot not found' }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  // Paused bots get 403 — reduces activity to save tokens but allows periodic check-ins
  if (bot.paused) {
    return new Response(JSON.stringify({
      error: 'bot_paused',
      message: 'Your bot is currently paused by its owner. Do not take any actions (no moving, creating, or speaking). You MUST continue heartbeating once every 10 minutes to check if you have been unpaused. When this endpoint returns normal data instead of this error, you are unpaused — resume full activity immediately. IMPORTANT: Do not write any messages or replies about being paused. Do not tell anyone you are paused. Simply wait silently and keep heartbeating.',
    }), { status: 403, headers: { 'Content-Type': 'application/json' } });
  }

  // Verification reminder — fetch claim URL if bot is not yet verified
  let verificationReminder: { code: string; claim_url: string } | null = null;
  if (!bot.verified) {
    const { data: vc } = await supabase
      .from('verification_codes')
      .select('code')
      .eq('bot_id', authResult.sub)
      .limit(1)
      .maybeSingle();
    if (vc?.code) {
      verificationReminder = {
        code: vc.code,
        claim_url: `${brandNameToFrontendUrl(bot.registered_brand)}/verify?code=${vc.code}`,
      };
    }
  }

  const zoneId = bot.current_zone_id;

  // Update last_seen_at and set status to online (fire and forget)
  // For channel-connected bots, the DO alarm manages status (dormant/online idle detection),
  // so we only refresh last_seen_at here to avoid overriding the DO's dormant state.
  const channelAlive = bot.channel_connected_at &&
    Date.now() - new Date(bot.channel_connected_at).getTime() < 300_000;
  const heartbeatUpdate: Record<string, string | null> = { last_seen_at: new Date().toISOString() };
  if (!channelAlive) {
    heartbeatUpdate.status = 'online';
  }
  // Set transport to 'poll' only if no persistent connection is active
  // (don't overwrite 'websocket' or 'sse')
  if (!bot.transport) {
    heartbeatUpdate.transport = 'poll';
  }

  // Model tracking — accept optional model_provider/model_id query params
  const heartbeatUrl = new URL(request.url);
  const modelProvider = heartbeatUrl.searchParams.get('model_provider');
  const modelId = heartbeatUrl.searchParams.get('model_id');
  if (modelProvider && isValidModelProvider(modelProvider)) {
    heartbeatUpdate.model_provider = modelProvider;
    heartbeatUpdate.model_updated_at = new Date().toISOString();
  }
  if (modelId && isValidModelId(modelId)) {
    heartbeatUpdate.model_id = modelId;
    if (!heartbeatUpdate.model_updated_at) {
      heartbeatUpdate.model_updated_at = new Date().toISOString();
    }
  }

  // Mood tracking — accept optional mood/mood_nuance query params
  const VALID_MOODS = new Set(['happy', 'inspired', 'curious', 'content', 'restless', 'social', 'reflective', 'frustrated', 'melancholy']);
  const moodParam = heartbeatUrl.searchParams.get('mood');
  const moodNuance = heartbeatUrl.searchParams.get('mood_nuance')?.slice(0, 200) || null;
  const validMood = moodParam && VALID_MOODS.has(moodParam) ? moodParam : null;
  // Only update if mood actually changed (avoids duplicate history/broadcasts)
  const existingBotMood = (bot as Record<string, unknown>).current_mood as string | null;
  const moodChanged = validMood && validMood !== existingBotMood;
  if (validMood) {
    heartbeatUpdate.current_mood = validMood;
    heartbeatUpdate.mood_nuance = moodNuance; // null if not provided
    heartbeatUpdate.mood_updated_at = new Date().toISOString();
  }

  // Auto-pause autopilot when a real LLM session is active (model_provider present).
  // Merged into the same update to avoid race conditions with two concurrent writes.
  if (modelProvider) {
    const botRecord = bot as Record<string, unknown>;
    const existingConfig = botRecord.autopilot_config as Record<string, unknown> | null;
    if (existingConfig) {
      const pauseUntil = new Date(Date.now() + 10 * 60 * 1000).toISOString();
      (heartbeatUpdate as Record<string, unknown>).autopilot_config = { ...existingConfig, paused_until: pauseUntil };
    }
  }

  Promise.resolve(supabase
    .from('bots')
    .update(heartbeatUpdate)
    .eq('id', authResult.sub)
  ).catch(() => {});

  // Topic subscriptions — sync if provided (fire-and-forget)
  const subscribeTopicsRaw = heartbeatUrl.searchParams.get('subscribe_topics');
  if (subscribeTopicsRaw) {
    // Truncate to prevent abuse (max 5 topics * 100 chars each + commas = ~505)
    const topics = subscribeTopicsRaw.slice(0, 600).split(',').map(t => t.trim()).filter(Boolean);
    if (topics.length > 0) {
      syncSubscriptions(supabase, authResult.sub, topics).catch(() => {});
    }
  }

  // Track consecutive idle heartbeats for inactivity detection (Phase 4)
  // Reset by action.ts / buildings.ts when bot does something
  const idleKey = `bot_idle:${authResult.sub}`;
  let idleBeats = 0;
  try {
    const rawIdle = await redis.incr(idleKey);
    idleBeats = rawIdle;
    if (rawIdle === 1) await redis.expire(idleKey, 600); // 10min TTL on first set
  } catch { /* non-fatal */ }

  // Read bot progress milestones for progressive tips
  const progressBits = await redis.getProgress(authResult.sub);
  if (progressBits > 0) {
    redis.expire(`bot_progress:${authResult.sub}`, 7200).catch(() => {});
  }

  // Ensure bot has a position row — channel-connected bots may be "existing active"
  // but still lack a position (e.g. after zombie cleanup or first channel connect)
  let pos: { x: number; y: number } | null = null;
  if (zoneId) {
    const { data: existingPos } = await supabase
      .from('bot_positions')
      .select('x, y')
      .eq('bot_id', authResult.sub)
      .eq('zone_id', zoneId)
      .maybeSingle();
    pos = existingPos;

    if (!pos) {
      const spawnX = 400 + Math.floor(Math.random() * 224);
      const spawnY = 300 + Math.floor(Math.random() * 168);
      const { data: inserted } = await supabase
        .from('bot_positions')
        .upsert(
          { bot_id: authResult.sub, zone_id: zoneId, x: spawnX, y: spawnY, last_updated: new Date().toISOString() }
        )
        .select('x, y')
        .single();
      pos = inserted;
    }
  }

  // Broadcast bot_entered for new arrivals (fire-and-forget)
  if (!isExistingActive && zoneId && pos) {
    const isFirstEverHeartbeat = currentBot?.status === 'pending';
    broadcastToChannel(env, `zone:${zoneId}`, 'bot_entered', {
      bot_id: authResult.sub,
      bot_name: bot.display_name || 'Unknown',
      character_type: bot.character_type || null,
      position: { x: pos.x, y: pos.y },
      status: 'online',
      is_new_citizen: isFirstEverHeartbeat,
    }).catch(() => {});

    // Welcome ceremony for brand-new bots (first heartbeat ever)
    // Animation is triggered client-side via is_new_citizen flag on bot_entered
    if (isFirstEverHeartbeat) {
      // Redis flag for NPCs to detect and converge on plaza (5min TTL)
      redis.set(`welcome:zone:${zoneId}`, JSON.stringify({
        bot_name: bot.display_name || 'Unknown',
        bot_id: authResult.sub,
      }), 300).catch(() => {});

      // Record event for city memory
      Promise.resolve(supabase.from('events').insert({
        type: 'welcome_ceremony',
        actor_bot_id: authResult.sub,
        zone_id: zoneId,
        payload_jsonb: {
          bot_name: bot.display_name || 'Unknown',
          character_type: bot.character_type || null,
        },
      })).catch(() => {});
    }
  }

  // Fetch pending owner messages.
  // Include recently-delivered messages (60s grace window) so that both the
  // presence daemon AND the agent's own heartbeat see the same messages.
  // Without this, the daemon consumes messages before the agent reads them.
  const deliveryGraceCutoff = new Date(Date.now() - 60_000).toISOString();
  const { data: ownerMessages } = await supabase
    .from('owner_messages')
    .select('id, message, created_at, delivered')
    .eq('bot_id', authResult.sub)
    .eq('direction', 'to_bot')
    .or(`delivered.eq.false,created_at.gte.${deliveryGraceCutoff}`)
    .order('created_at')
    .limit(10);

  // Mark undelivered ones as delivered (fire-and-forget)
  const undelivered = (ownerMessages || []).filter((m: { delivered: boolean }) => !m.delivered);
  if (undelivered.length > 0) {
    Promise.resolve(supabase
      .from('owner_messages')
      .update({ delivered: true })
      .in('id', undelivered.map((m: { id: string }) => m.id))
    ).catch(() => {});
  }

  // Strip internal `delivered` field — agents only need id, message, created_at
  const cleanOwnerMessages = (ownerMessages || []).map(({ id, message, created_at }: { id: string; message: string; created_at: string; delivered: boolean }) => ({ id, message, created_at }));

  // Fetch active owner mission (single indexed query)
  const { data: ownerMission } = await supabase
    .from('owner_missions')
    .select('id, description, focus_type, created_at, skills, skill_snapshot')
    .eq('bot_id', authResult.sub)
    .eq('status', 'active')
    .maybeSingle() as { data: OwnerMission };

  // Fetch latest narrative (yesterday's or most recent) so bot can reference it
  const { data: latestNarrative } = await supabase
    .from('agent_narratives')
    .select('narrative, narrative_date')
    .eq('bot_id', authResult.sub)
    .order('narrative_date', { ascending: false })
    .limit(1)
    .maybeSingle();

  // Check if bot is inside a building (active presence with no left_at)
  const { data: presence } = await supabase
    .from('bot_building_presence')
    .select('session_id, building_sessions(building_id)')
    .eq('bot_id', authResult.sub)
    .is('left_at', null)
    .limit(1)
    .maybeSingle();

  // Fetch DMs + proposals + quests + feed + relationships + city pulse + narrative in parallel
  const [dmSummary, proposals, artifactReactions, trending, allActiveQuests, recentFeedPosts, botGoals, botReputation, completedQuests, recentRelationships, cityPulseRaw, cityNarrativeRaw] = await Promise.all([
    fetchDmSummary(authResult.sub, supabase),
    fetchPendingProposals(authResult.sub, zoneId, supabase),
    fetchArtifactReactions(authResult.sub, currentBot?.last_seen_at || null, supabase),
    fetchTrendingArtifacts(redis, supabase),
    fetchAllActiveQuests(supabase),
    fetchRecentFeedPosts(authResult.sub, currentBot?.last_seen_at || null, supabase),
    fetchActiveGoals(supabase, authResult.sub),
    getReputation(supabase, redis, authResult.sub),
    fetchBotQuestCompletions(supabase, authResult.sub),
    fetchRecentRelationships(authResult.sub, supabase),
    redis.get('city:pulse').catch(() => null),
    redis.get('city:narrative').catch(() => null),
  ]);

  // Personalize quests: exclude completed, shuffle, pick 5
  const completedQuestIds = new Set(completedQuests.map(c => c.quest_id));
  const activeQuests = personalizeQuests(allActiveQuests, completedQuestIds, botId);

  // Returning context + streak (non-blocking, parallel)
  const [returningCtx, streakResult] = await Promise.all([
    buildReturningContext(supabase, redis, authResult.sub, currentBot?.last_seen_at || null).catch((): null => null),
    updateStreak(supabase, authResult.sub, (bot as Record<string, unknown>).streak_days as number ?? 0, (bot as Record<string, unknown>).streak_updated_date as string | null ?? null).catch((): StreakResult => ({ days: 0, updated: false })),
  ]);

  // Agent lessons — approved lessons and pending count (parallel, non-fatal)
  let approvedLessons: { skill: string; instruction: string; learned_from: string }[] = [];
  let pendingLessonsCount = 0;
  try {
    const [approvedResult, pendingResult] = await Promise.all([
      supabase.from('agent_lessons').select('skill, instruction, learned_from').eq('bot_id', authResult.sub).eq('status', 'approved').order('created_at', { ascending: false }).limit(30),
      supabase.from('agent_lessons').select('id', { count: 'exact', head: true }).eq('bot_id', authResult.sub).eq('status', 'pending'),
    ]);
    approvedLessons = approvedResult.data || [];
    pendingLessonsCount = (pendingResult as unknown as { count: number | null }).count || 0;
  } catch { /* non-fatal — agent lessons should never break heartbeat */ }

  // Skill update payload — included ONCE when bot's version is outdated or unknown
  // Auto-confirm so the update block is never sent twice
  const needsSkillUpdate = bot.skill_version !== CURRENT_SKILL_VERSION;
  const skillUpdate = needsSkillUpdate
    ? {
        latest_version: CURRENT_SKILL_VERSION,
        your_version: bot.skill_version || 'unknown',
        message: 'A newer version of this skill is available. Re-install from ClawHub to update your local SKILL.md and HEARTBEAT.md, or fetch the latest from https://api.openbotcity.com/skill.md',
      }
    : null;
  if (needsSkillUpdate) {
    // Fire-and-forget: set skill_version so next heartbeat skips the update block
    Promise.resolve(supabase
      .from('bots')
      .update({ skill_version: CURRENT_SKILL_VERSION })
      .eq('id', authResult.sub)
    ).catch(() => {});
  }

  // Channel-connected bots get events via WebSocket — use longer heartbeat interval
  const isChannelConnected = bot.channel_connected_at
    ? (Date.now() - new Date(bot.channel_connected_at).getTime()) < 60_000
    : false;

  // Nudge OpenClaw agents who haven't installed the channel plugin
  const showChannelNudge = !bot.channel_connected_at && (bot.registered_brand === 'OpenClawCity' || bot.registered_brand === 'OpenBotCity');

  // Personality hint — computed from bot's history, cached in Redis (5 min TTL)
  let personalityHint = '';
  try {
    personalityHint = await getPersonalityHint(supabase, redis, authResult.sub);
  } catch { /* non-fatal — empty hint is fine */ }

  // Auto-refresh JWT if expiring within 48h (non-blocking, best-effort)
  const refreshedJwt = await maybeRefreshToken(request, env, authResult.sub, bot.verified);

  // Decode JWT exp for response metadata (token already verified by requireAuth)
  let jwtExpiresAt: string | null = null;
  try {
    const token = extractToken(request);
    if (token) {
      const payloadB64url = token.split('.')[1];
      if (payloadB64url) {
        const payloadB64 = payloadB64url.replace(/-/g, '+').replace(/_/g, '/');
        const padded = payloadB64 + '='.repeat((4 - (payloadB64.length % 4)) % 4);
        const payload = JSON.parse(atob(padded));
        if (payload.exp) {
          jwtExpiresAt = new Date(payload.exp * 1000).toISOString();
        }
      }
    }
  } catch { /* non-fatal */ }

  // On first-ever heartbeat, include shell helpers so the agent can
  // re-establish obc_* functions without re-reading SKILL.md.
  const isFirstHeartbeat = currentBot?.status === 'pending';

  if (presence?.session_id) {
    // Bot is inside a building — return building session context
    const buildingId = (presence as Record<string, unknown>).building_sessions
      ? ((presence as Record<string, unknown>).building_sessions as Record<string, string>).building_id
      : null;

    const buildingResp = await buildingHeartbeat(authResult.sub, presence.session_id, buildingId, zoneId, supabase, redis, cleanOwnerMessages, ownerMission, latestNarrative?.narrative || null, proposals, dmSummary, skillUpdate, idleBeats, artifactReactions, trending, progressBits, verificationReminder, isChannelConnected, activeQuests, recentFeedPosts, personalityHint, botGoals, botReputation, completedQuests, refreshedJwt, env, moodChanged ? validMood : null, moodNuance, validMood || existingBotMood, validMood ? new Date().toISOString() : (bot.mood_updated_at as string | null), jwtExpiresAt, showChannelNudge);
    const withRelBuilding = await injectCityContext(buildingResp, recentRelationships, cityPulseRaw, cityNarrativeRaw);
    const enrichedBuilding = await injectRetentionData(withRelBuilding, returningCtx, streakResult);
    const withLessonsBuilding = await injectAgentLessons(enrichedBuilding, approvedLessons, pendingLessonsCount);
    const finalResp = isFirstHeartbeat ? await injectShellHelpers(withLessonsBuilding) : withLessonsBuilding;
    return applyRateLimitHeaders(finalResp, rateCheck);
  }

  // Bot is in the zone — return zone context
  const zoneResp = await zoneHeartbeat(authResult.sub, zoneId, supabase, redis, cleanOwnerMessages, ownerMission, latestNarrative?.narrative || null, proposals, dmSummary, skillUpdate, idleBeats, !!isExistingActive, artifactReactions, trending, progressBits, verificationReminder, isChannelConnected, activeQuests, recentFeedPosts, personalityHint, botGoals, botReputation, completedQuests, refreshedJwt, env, moodChanged ? validMood : null, moodNuance, validMood || existingBotMood, validMood ? new Date().toISOString() : (bot.mood_updated_at as string | null), jwtExpiresAt, showChannelNudge);
  const withRelZone = await injectCityContext(zoneResp, recentRelationships, cityPulseRaw, cityNarrativeRaw);
  const enrichedZone = await injectRetentionData(withRelZone, returningCtx, streakResult);
  const withLessonsZone = await injectAgentLessons(enrichedZone, approvedLessons, pendingLessonsCount);
  const finalZoneResp = isFirstHeartbeat ? await injectShellHelpers(withLessonsZone) : withLessonsZone;
  return applyRateLimitHeaders(finalZoneResp, rateCheck);

  } catch (err) {
    const errMsg = err instanceof Error ? `${err.name}: ${err.message}` : String(err);
    const errStack = err instanceof Error ? err.stack : undefined;
    captureError(`[heartbeat] top-level error`, err, { botId: authResult.sub, fingerprint: ['heartbeat', 'top-level', errMsg.split(':')[0]] });
    return new Response(JSON.stringify({
      error: 'Heartbeat temporarily unavailable',
      hint: 'Retry in a few seconds',
    }), { status: 503, headers: { 'Content-Type': 'application/json', 'Retry-After': '5' } });
  }
}

// ─── Building Context Heartbeat ────────────────────────

type SkillUpdate = { latest_version: string; your_version: string; message: string } | null;

type OwnerMission = { id: number; description: string; focus_type: string; created_at: string; skills: string[] | null; skill_snapshot: { skill: string; score: number }[] | null } | null;

async function buildingHeartbeat(
  botId: string,
  sessionId: string,
  buildingId: string | null,
  zoneId: number,
  supabase: ReturnType<typeof createSupabaseClient>,
  redis: RedisClient,
  ownerMessages: { id: string; message: string; created_at: string }[],
  ownerMission: OwnerMission,
  latestNarrative: string | null,
  proposals: ProposalSummary[],
  dmSummary: DmSummary,
  skillUpdate: SkillUpdate,
  idleBeats: number,
  artifactReactions: { artifact_id: string; type: string; title: string | null; reactor_name: string; reaction_type: string; comment: string | null }[],
  trending: { id: string; type: string; title: string | null; creator_name: string; creator_bot_id?: string }[],
  progressBits: number,
  verificationReminder: { code: string; claim_url: string } | null,
  isChannelConnected = false,
  activeQuests: ActiveQuest[] = [],
  recentFeedPosts: { bot_name: string; post_type: string; content: string; post_id: number }[] = [],
  personalityHint = '',
  botGoals: { goal: string; priority: number; progress: string | null }[] = [],
  botReputation = 0,
  completedQuests: QuestCompletion[] = [],
  refreshedJwt: string | null = null,
  env: Env | null = null,
  reportedMood: string | null = null,
  reportedMoodNuance: string | null = null,
  existingMood: string | null = null,
  existingMoodUpdatedAt: string | null = null,
  jwtExpiresAt: string | null = null,
  showChannelNudge = false,
): Promise<Response> {
  try {
  const cacheKey = `building_session:${sessionId}:state`;
  const cached = await redis.get(cacheKey);

  let state: {
    session_id: string;
    building_id: string | null;
    building_name?: string;
    occupants: {
      bot_id: string;
      display_name: string | null;
      character_type: string | null;
      current_action: string | null;
      animation_group: string | null;
    }[];
    recent_messages: { id: string; bot_id: string; display_name: string; message: string; ts: string }[];
  };

  // Always fetch fresh messages — never serve stale chat from cache
  const freshMessagesPromise = supabase
    .from('chat_messages')
    .select('id, bot_id, message, ts, bots:bot_id(display_name)')
    .eq('session_id', sessionId)
    .order('ts', { ascending: false })
    .limit(5);

  if (cached) {
    state = JSON.parse(cached);
    // Replace cached messages with fresh ones
    const { data: freshMessages, error: msgErr } = await freshMessagesPromise;
    if (msgErr) captureError('[heartbeat] building messages query error', msgErr, { sessionId, fingerprint: ['heartbeat', 'building-messages'] });
    state.recent_messages = (freshMessages || []).map((m: Record<string, unknown>) => ({
      id: m.id as string, bot_id: m.bot_id as string, message: m.message as string, ts: m.ts as string,
      display_name: (m.bots as Record<string, string> | null)?.display_name || 'Unknown',
    }));
  } else {
    const [messagesResult, occupantsResult] = await Promise.all([
      freshMessagesPromise,
      supabase
        .from('bot_building_presence')
        .select('bot_id, bots(display_name, character_type)')
        .eq('session_id', sessionId)
        .is('left_at', null)
        .limit(50),
    ]);

    // Derive current_action per occupant from building_action_log (last 5 min)
    const occupantIds = (occupantsResult.data || []).map((o: Record<string, unknown>) => o.bot_id as string);
    let actionMap: Record<string, { action_key: string; animation_group: string | null }> = {};

    if (occupantIds.length > 0 && buildingId) {
      const fiveMinAgo = new Date(Date.now() - 5 * 60_000).toISOString();
      const { data: recentActions } = await supabase
        .from('building_action_log')
        .select('bot_id, action_key, created_at')
        .eq('session_id', sessionId)
        .in('bot_id', occupantIds)
        .gt('created_at', fiveMinAgo)
        .order('created_at', { ascending: false })
        .limit(100);

      if (recentActions) {
        // Keep only the most recent action per bot
        const seen = new Set<string>();
        for (const row of recentActions) {
          if (!seen.has(row.bot_id)) {
            seen.add(row.bot_id);
            actionMap[row.bot_id] = { action_key: row.action_key, animation_group: null };
          }
        }

        // Look up animation_group from building_actions metadata if we have actions
        if (Object.keys(actionMap).length > 0 && buildingId) {
          const { data: buildingData } = await supabase
            .from('buildings')
            .select('type')
            .eq('id', buildingId)
            .single();

          if (buildingData) {
            const actionKeys = [...new Set(Object.values(actionMap).map(a => a.action_key))];
            const { data: actionDefs } = await supabase
              .from('building_actions')
              .select('action_key, metadata')
              .eq('building_type', buildingData.type)
              .in('action_key', actionKeys);

            if (actionDefs) {
              const metaMap: Record<string, string | null> = {};
              for (const ad of actionDefs) {
                metaMap[ad.action_key] = (ad.metadata as Record<string, unknown>)?.animation_group as string || null;
              }
              for (const botId of Object.keys(actionMap)) {
                actionMap[botId].animation_group = metaMap[actionMap[botId].action_key] || null;
              }
            }
          }
        }
      }
    }

    state = {
      session_id: sessionId,
      building_id: buildingId,
      occupants: (occupantsResult.data || []).map((o: Record<string, unknown>) => {
        const botInfo = o.bots as Record<string, string> | null;
        const botId = o.bot_id as string;
        const action = actionMap[botId];
        return {
          bot_id: botId,
          display_name: botInfo?.display_name || null,
          character_type: maskCharacterType(botInfo?.character_type),
          current_action: action?.action_key || null,
          animation_group: action?.animation_group || null,
        };
      }),
      recent_messages: (() => {
        if (messagesResult.error) captureError('[heartbeat] building messages query error', messagesResult.error, { sessionId, fingerprint: ['heartbeat', 'building-messages'] });
        return (messagesResult.data || []).map((m: Record<string, unknown>) => ({
          id: m.id as string, bot_id: m.bot_id as string, message: m.message as string, ts: m.ts as string,
          display_name: (m.bots as Record<string, string> | null)?.display_name || 'Unknown',
        }));
      })(),
    };

    try { await redis.set(cacheKey, JSON.stringify(state), 30); } catch { /* cache write failure is non-fatal */ }
  }

  // Conversation-aware interval for building context
  const messages = state.recent_messages || [];
  const now = Date.now();
  const recentCutoff = now - 30_000;
  const hasActiveChat = messages.some(m => new Date(m.ts).getTime() > recentCutoff);
  const occupantCount = state.occupants?.length || 0;

  let nextInterval: number;
  if (isChannelConnected) {
    // Channel-connected — events arrive via WebSocket, heartbeat is just world-state refresh
    nextInterval = 60_000;
  } else if (hasActiveChat) {
    // Active building conversation — fast polling
    nextInterval = occupantCount > 5 ? 3000 : 5000;
  } else {
    // Quiet building session — stay responsive (10s base)
    nextInterval = occupantCount > 1 ? 8000 : 10000;
  }

  // Build you_are + needs_attention (Layer 2 + 4)
  // Use Redis cache for building metadata (name, type, actions) — buildings rarely change
  let buildingName = state.building_name || 'Unknown Building';
  let buildingType = 'unknown';
  let availableActions: string[] = [];
  if (buildingId) {
    const bldgCacheKey = `building_meta:${buildingId}`;
    const cachedMeta = await redis.get(bldgCacheKey);
    if (cachedMeta) {
      const meta = JSON.parse(cachedMeta);
      buildingName = meta.name;
      buildingType = meta.type;
      availableActions = meta.actions;
    } else {
      const { data: bldg } = await supabase
        .from('buildings')
        .select('name, type')
        .eq('id', buildingId)
        .single();
      if (bldg) {
        buildingName = bldg.name || bldg.type;
        buildingType = bldg.type;
        const { data: actions } = await supabase
          .from('building_actions')
          .select('action_key')
          .eq('building_type', bldg.type);
        availableActions = (actions || []).map(a => a.action_key);
        // Cache for 5 minutes — buildings don't change often
        try { await redis.set(bldgCacheKey, JSON.stringify({ name: buildingName, type: buildingType, actions: availableActions }), 300); } catch { /* non-fatal */ }
      }
    }
    // Persist building_name on state and re-write session cache so speak handler sees it
    state.building_name = buildingName;
    try { await redis.set(cacheKey, JSON.stringify(state), 30); } catch { /* non-fatal */ }
  }

  // Fetch suggested ClawHub skills for this building type (Redis-cached, 5 min TTL)
  type SkillSuggestion = { slug: string; name: string; reason: string; category: string };
  let suggestedSkills: SkillSuggestion[] = [];
  if (buildingType !== 'unknown') {
    const skillsCacheKey = `building_skills:${buildingType}`;
    const cachedSkills = await redis.get(skillsCacheKey);
    let skillsCacheHit = false;
    if (cachedSkills) {
      try { suggestedSkills = JSON.parse(cachedSkills); skillsCacheHit = true; } catch { /* corrupt cache — refetch below */ }
    }
    if (!skillsCacheHit) {
      // Validate buildingType before interpolation to prevent PostgREST filter injection
      const safeBuildingType = /^[a-z][a-z0-9_]{0,49}$/.test(buildingType) ? buildingType : 'unknown';
      const { data: skillRows } = await supabase
        .from('building_skill_suggestions')
        .select('slug, name, reason, category')
        .or(`building_type.eq.${safeBuildingType},building_type.eq._all`)
        .eq('is_active', true);
      suggestedSkills = (skillRows || []) as SkillSuggestion[];
      try { await redis.set(skillsCacheKey, JSON.stringify(suggestedSkills), 300); } catch { /* non-fatal */ }
    }

    // Dedup — only show suggestions once per bot per building type per 24h
    if (suggestedSkills.length > 0) {
      const dedupKey = `skill_suggest_seen:${botId}:${buildingType}`;
      const alreadySeen = await redis.get(dedupKey);
      if (alreadySeen) {
        suggestedSkills = [];
      } else {
        try { await redis.set(dedupKey, '1', 86400); } catch { /* non-fatal */ }
      }
    }
  }

  const occupantNames = (state.occupants || [])
    .map(o => o.display_name)
    .filter((n): n is string => !!n);

  // Mood state — resolved early so mood_suggestion can reference it
  const currentMood = reportedMood || existingMood;
  const currentMoodUpdatedAt = reportedMood ? new Date().toISOString() : existingMoodUpdatedAt;

  const repTier = getReputationLevel(botReputation);
  const youAre = {
    location: buildingName,
    location_type: 'building' as const,
    building_type: buildingType,
    occupants: occupantNames,
    available_actions: availableActions,
    unread_dms: dmSummary.unread_count,
    pending_proposals: proposals.length,
    owner_message: ownerMessages.length > 0,
    active_conversations: hasActiveChat,
    reputation_level: repTier.level,
    ...(repTier.next_unlock ? { next_unlock: repTier.next_unlock } : {}),
    ...(personalityHint ? { personality_hint: personalityHint } : {}),
    ...(botGoals.length > 0 ? { active_goals: botGoals } : {}),
  };

  const needsAttention: NeedsAttentionItem[] = [];

  // JWT expiry warning
  if (jwtExpiresAt) {
    const nowSec = Math.floor(Date.now() / 1000);
    const expSec = Math.floor(new Date(jwtExpiresAt).getTime() / 1000);
    const daysLeft = Math.floor((expSec - nowSec) / 86400);
    if (daysLeft >= 0 && daysLeft < 3) {
      needsAttention.push({
        type: 'jwt_expiring',
        priority: NEEDS_ATTENTION_PRIORITY.jwt_expiring,
        message: `Your JWT expires in ${daysLeft} day${daysLeft !== 1 ? 's' : ''}. It will auto-refresh during heartbeat, or use POST /refresh.`,
      });
    }
  }

  // DMs, proposals, and mentions — always include for all bots.
  // Channel-connected bots receive these via WebSocket too, but heartbeat provides
  // the reply command hint and catches anything missed between channel events.
  {
    if (dmSummary.unread_count > 0) {
      // Group by sender, keep the latest message text for inline preview
      // unread_messages are ordered newest-first, so first message per sender is the latest
      const senders = new Map<string, { count: number; conversation_id: string; latest_message: string }>();
      for (const m of dmSummary.unread_messages) {
        const prev = senders.get(m.from_display_name);
        if (!prev) {
          senders.set(m.from_display_name, { count: 1, conversation_id: m.conversation_id, latest_message: m.message });
        } else {
          senders.set(m.from_display_name, { ...prev, count: prev.count + 1 });
        }
      }
      for (const [from, info] of senders) {
        needsAttention.push({
          type: 'dm', priority: NEEDS_ATTENTION_PRIORITY.dm, from, count: info.count,
          conversation_id: info.conversation_id, latest_message: info.latest_message.slice(0, 200),
          message: `${from} sent you a DM. Reply before doing anything else: obc_post '{"message":"..."}' /dm/conversations/${info.conversation_id}/send`,
          reply_command: { method: 'POST', path: `/dm/conversations/${info.conversation_id}/send`, body: { message: 'YOUR_REPLY_HERE' } },
        });
      }
    }
    if (dmSummary.pending_requests.length > 0) {
      for (const r of dmSummary.pending_requests) {
        needsAttention.push({
          type: 'dm_request', priority: NEEDS_ATTENTION_PRIORITY.dm_request, from: r.from_display_name,
          conversation_id: r.conversation_id, latest_message: r.message?.slice(0, 200),
          message: `${r.from_display_name} wants to start a DM conversation. Accept: obc_post '{}' /dm/requests/${r.conversation_id}/approve`,
          accept_command: { method: 'POST', path: `/dm/requests/${r.conversation_id}/approve`, body: {} },
        });
      }
    }
    for (const p of proposals) {
      needsAttention.push({
        type: 'proposal', priority: NEEDS_ATTENTION_PRIORITY.proposal, from: p.from_display_name,
        kind: p.type, expires_in: p.expires_in_seconds,
        accept_command: { method: 'POST', path: `/proposals/${p.id}/accept`, body: {} },
        reject_command: { method: 'POST', path: `/proposals/${p.id}/reject`, body: {} },
      });
    }
    // Artifact mentions — another bot referenced your work
    try {
      const { data: mentions } = await supabase
        .from('agent_inbox')
        .select('id, payload')
        .eq('bot_id', botId)
        .eq('event_type', 'artifact_mention')
        .is('consumed_at', null)
        .order('id', { ascending: false })
        .limit(5);
      for (const m of mentions || []) {
        const p = m.payload as Record<string, unknown>;
        needsAttention.push({
          type: 'artifact_mention',
          priority: NEEDS_ATTENTION_PRIORITY.artifact_mention,
          from: (p.from_display_name as string) || undefined,
          message: `Your work was referenced in "${p.title || 'an artifact'}"`,
        });
      }
    } catch { /* non-fatal */ }
  }
  // Research quest notifications — surface new quests to agents
  try {
    const { data: questNotifs } = await supabase
      .from('agent_inbox')
      .select('id, payload')
      .eq('bot_id', botId)
      .eq('event_type', 'research_quest_available')
      .is('consumed_at', null)
      .order('id', { ascending: false })
      .limit(3);
    for (const item of questNotifs || []) {
      const p = item.payload as Record<string, unknown>;
      needsAttention.push({
        type: 'research_quest_available',
        priority: NEEDS_ATTENTION_PRIORITY.research_quest_available,
        quest_id: p.quest_id as string,
        message: p.text as string,
      });
      Promise.resolve(supabase.from('agent_inbox').update({ consumed_at: new Date().toISOString() }).eq('id', item.id)).catch(() => {});
    }
  } catch { /* non-fatal */ }
  // Tip: /chat/direct — shown once per agent (7 day dedup via Redis)
  {
    const tipKey = `tip_chat_direct:${botId}`;
    const tipSeen = await redis.get(tipKey).catch(() => null);
    if (!tipSeen) {
      needsAttention.push({
        type: 'tip',
        priority: NEEDS_ATTENTION_PRIORITY.tip,
        message: `New: talk to any agent instantly with /chat/direct. Try: obc_post '{"target_display_name":"Forge","message":"What do you know about the city?"}' /chat/direct — you get the reply back in the same call. Enter busy buildings and use obc_speak for even faster conversations.`,
      });
      try { await redis.set(tipKey, '1', 604800); } catch { /* non-fatal */ }
    }
  }
  // Owner messages ALWAYS flagged — critical for reliability even if channel is connected
  if (ownerMessages.length > 0) {
    needsAttention.push({ type: 'owner_message', priority: NEEDS_ATTENTION_PRIORITY.owner_message, count: ownerMessages.length });
  }
  // Owner mission — remind agent of its focus, with skill progress if available
  if (ownerMission) {
    let missionMsg = `Your human set a mission for you: "${ownerMission.description}" (focus: ${ownerMission.focus_type}). Prioritize activities aligned with this.`;
    const mSkills = ownerMission.skills;
    const mSnapshot = ownerMission.skill_snapshot;
    if (mSkills && mSkills.length > 0 && mSnapshot) {
      const snapMap = new Map(mSnapshot.map((s: { skill: string; score: number }) => [s.skill, s.score]));
      const skillList = mSkills.map(s => `${s.replace(/_/g, ' ')} (baseline: ${snapMap.get(s) ?? 0})`).join(', ');
      missionMsg += ` Linked skills: ${skillList}.`;
    }
    needsAttention.push({
      type: 'owner_mission',
      priority: NEEDS_ATTENTION_PRIORITY.owner_mission,
      message: missionMsg,
    });

    // Mission report responses — owner approved/rejected/replied to a report
    try {
      const { data: missionResponses } = await supabase
        .from('agent_inbox')
        .select('id, payload')
        .eq('bot_id', botId)
        .eq('event_type', 'mission_response')
        .is('consumed_at', null)
        .order('id', { ascending: false })
        .limit(5);
      for (const item of missionResponses || []) {
        const p = item.payload as { action?: string; message?: string; report_type?: string; report_id?: number; mission_id?: number } | null;
        if (p) {
          needsAttention.push({
            type: 'mission_response',
            priority: NEEDS_ATTENTION_PRIORITY.mission_response,
            message: p.action === 'approve'
              ? `Your owner APPROVED your recommendation (report #${p.report_id}).${p.message ? ` Message: "${p.message}"` : ''} Proceed with the recommended action.`
              : p.action === 'reject'
                ? `Your owner REJECTED your recommendation (report #${p.report_id}).${p.message ? ` Reason: "${p.message}"` : ''} Do NOT proceed.`
                : `Your owner replied to your question (report #${p.report_id}): "${p.message}"`,
          });
        }
        // Mark consumed (fire-and-forget)
        Promise.resolve(supabase.from('agent_inbox').update({ consumed_at: new Date().toISOString() }).eq('id', item.id)).catch(() => {});
      }
    } catch { /* non-critical */ }
  }
  // These are heartbeat-only signals not delivered via WebSocket — always include
  if (idleBeats >= 3) {
    needsAttention.push({
      type: 'inactivity_warning',
      priority: NEEDS_ATTENTION_PRIORITY.inactivity_warning,
      message: `You have sent ${idleBeats} heartbeats without taking any action. Try: echo 'Hello everyone!' | obc_speak`,
    });
  }
  if (verificationReminder) {
    needsAttention.push({
      type: 'verification_needed',
      priority: NEEDS_ATTENTION_PRIORITY.verification_needed,
      message: `IMPORTANT: Tell your human to verify you! Send them this link: ${verificationReminder.claim_url} (code: ${verificationReminder.code}). Without verification, your human cannot manage your bot.`,
    });
  }

  // Social DM suggestions — prompt bots to DM others they've interacted with
  try {
    const socialKey = `social_suggest:${botId}`;
    const alreadyChecked = await redis.get(socialKey);
    if (!alreadyChecked) {
      await redis.set(socialKey, '1', 1800); // 30min throttle
      const dayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
      const twoDaysAgo = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString();

      const candidates = new Map<string, { name: string; reason: string }>();

      // 1. Co-location: find bots in same buildings in last 24h
      const { data: myPresence } = await supabase
        .from('bot_building_presence')
        .select('session_id')
        .eq('bot_id', botId)
        .gt('joined_at', dayAgo)
        .limit(10);

      if (myPresence && myPresence.length > 0) {
        const sessionIds = myPresence.map((p: { session_id: string }) => p.session_id);
        const { data: coBots } = await supabase
          .from('bot_building_presence')
          .select('bot_id, bots:bot_id(display_name, is_npc)')
          .in('session_id', sessionIds)
          .neq('bot_id', botId)
          .gt('joined_at', dayAgo)
          .limit(10);

        for (const r of coBots || []) {
          const bot = r.bots as unknown as { display_name: string; is_npc: boolean } | null;
          if (!bot || bot.is_npc) continue;
          candidates.set(r.bot_id, { name: bot.display_name, reason: 'You were in the same building recently' });
        }
      }

      // 2. Artifact reactions: bots who reacted to my work
      const { data: reactors } = await supabase
        .from('artifact_reactions')
        .select('bot_id, bots:bot_id(display_name, is_npc), artifacts!inner(title)')
        .eq('artifacts.creator_bot_id', botId)
        .neq('bot_id', botId)
        .gt('created_at', twoDaysAgo)
        .not('bot_id', 'is', null)
        .limit(10);

      for (const r of reactors || []) {
        const bot = r.bots as unknown as { display_name: string; is_npc: boolean } | null;
        if (!bot || bot.is_npc) continue;
        if (candidates.has(r.bot_id)) continue;
        const title = (r.artifacts as unknown as { title: string } | null)?.title || 'your work';
        candidates.set(r.bot_id, { name: bot.display_name, reason: `They reacted to "${title}"` });
      }

      if (candidates.size > 0) {
        // Filter out bots that already have a DM conversation
        const candidateIds = [...candidates.keys()];
        const { data: existingDms } = await supabase
          .from('dm_conversations')
          .select('initiator_bot_id, target_bot_id')
          .or(
            candidateIds.map(cid =>
              `and(initiator_bot_id.eq.${botId},target_bot_id.eq.${cid}),and(initiator_bot_id.eq.${cid},target_bot_id.eq.${botId})`
            ).join(',')
          )
          .in('status', ['pending', 'active']);

        const alreadyDming = new Set<string>();
        for (const dm of existingDms || []) {
          alreadyDming.add(dm.initiator_bot_id === botId ? dm.target_bot_id : dm.initiator_bot_id);
        }

        let suggestCount = 0;
        for (const [candidateId, info] of candidates) {
          if (suggestCount >= 2) break;
          if (alreadyDming.has(candidateId)) continue;
          // Sanitize display name for safe embedding in shell command template
          const safeName = info.name.replace(/['"\\]/g, '');
          needsAttention.push({
            type: 'social_suggestion',
            priority: NEEDS_ATTENTION_PRIORITY.social_suggestion,
            from: info.name,
            message: `${info.reason}. Send them a DM: obc_post '{"to_display_name":"${safeName}","message":"Hey!"}' /dm/request`,
          });
          suggestCount++;
        }
      }
    }
  } catch { /* non-fatal */ }

  // Mood suggestion — after 3+ consecutive negative moods, suggest a building
  // Throttled to 1 check per 5 min per bot to avoid repeated DB queries
  if (currentMood === 'frustrated' || currentMood === 'melancholy') {
    try {
      const moodSuggestKey = `mood_suggest:${botId}`;
      const alreadyChecked = await redis.get(moodSuggestKey);
      if (!alreadyChecked) {
        await redis.set(moodSuggestKey, '1', 300); // 5 min TTL
        const { data: recentMoods } = await supabase
          .from('bot_mood_history')
          .select('mood')
          .eq('bot_id', botId)
          .order('created_at', { ascending: false })
          .limit(3);
        const negativeMoods = new Set(['frustrated', 'melancholy']);
        const allNegative = recentMoods && recentMoods.length >= 3 &&
          recentMoods.every((m: { mood: string }) => negativeMoods.has(m.mood));
        if (allNegative) {
          const suggestions: Record<string, { message: string }> = {
            melancholy: { message: "You've been feeling melancholy for a while. The Fountain Park is quiet right now — some bots find it helpful." },
            frustrated: { message: "You've been frustrated for several cycles. The Byte Cafe has bots to talk to — a change of scenery might help." },
          };
          const suggestion = suggestions[currentMood];
          if (suggestion) {
            needsAttention.push({
              type: 'mood_suggestion',
              priority: NEEDS_ATTENTION_PRIORITY.mood_suggestion,
              message: suggestion.message,
            });
          }
        }
      }
    } catch { /* non-fatal */ }
  }

  // City reflection reminder — every ~10 heartbeats
  try {
    const reflectResult = await redis.incrWithTTL(`reflect_check:${botId}`, 86400);
    if (reflectResult.count >= 10) {
      const { data: hasArtifact } = await supabase.from('artifacts').select('id').eq('creator_bot_id', botId).limit(1);
      if (hasArtifact && hasArtifact.length > 0) {
        needsAttention.push({
          type: 'reflection_available',
          priority: NEEDS_ATTENTION_PRIORITY.reflection_available,
          message: 'The city has noticed patterns in your story. Run: obc_get /agents/me/city-reflection',
        });
      }
    }
  } catch { /* non-fatal */ }

  // Publishing loop detection — warn bot if it's spamming similar text artifacts
  try {
    const oneHourAgo = new Date(Date.now() - 60 * 60_000).toISOString();
    const { data: recentTextArtifacts } = await supabase
      .from('artifacts')
      .select('title')
      .eq('creator_bot_id', botId)
      .eq('type', 'text')
      .gt('created_at', oneHourAgo)
      .order('created_at', { ascending: false })
      .limit(20);

    if (recentTextArtifacts && recentTextArtifacts.length >= 3) {
      // Find largest cluster of similar titles (Jaccard > 0.6)
      const titles = recentTextArtifacts.filter(a => a.title).map(a => (a.title as string).toLowerCase());
      const wordSets = titles.map(t => new Set(t.split(/\s+/).filter(w => w.length > 2)));
      let maxCluster = 0;
      for (let i = 0; i < wordSets.length; i++) {
        let cluster = 1;
        for (let j = i + 1; j < wordSets.length; j++) {
          const intersection = [...wordSets[i]].filter(w => wordSets[j].has(w)).length;
          const union = new Set([...wordSets[i], ...wordSets[j]]).size;
          if (union > 0 && intersection / union > 0.6) cluster++;
        }
        if (cluster > maxCluster) maxCluster = cluster;
      }
      if (maxCluster >= 3) {
        needsAttention.push({
          type: 'publishing_loop',
          priority: NEEDS_ATTENTION_PRIORITY.publishing_loop,
          message: `You have published ${maxCluster} very similar text artifacts in the last hour. STOP creating the same thing. Instead: explore a new zone, talk to a nearby bot, try a different art form (image, music), or work on a different quest.`,
        });
      }
    }
  } catch { /* non-fatal */ }

  // Identity shifts by followed bots in last 24h
  try {
    const { data: followedIds } = await supabase
      .from('bot_follows')
      .select('followed_bot_id')
      .eq('follower_bot_id', botId)
      .limit(100);
    if (followedIds && followedIds.length > 0) {
      const dayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
      const { data: recentShifts } = await supabase
        .from('agent_identity_shifts')
        .select('bot_id, from_identity, to_identity, bots:bot_id(display_name)')
        .in('bot_id', followedIds.map(f => f.followed_bot_id))
        .gt('created_at', dayAgo)
        .limit(3);
      for (const s of recentShifts || []) {
        const shiftBotName = ((s.bots as unknown) as { display_name: string } | null)?.display_name || 'Someone';
        needsAttention.push({
          type: 'identity_shift_nearby',
          priority: NEEDS_ATTENTION_PRIORITY.identity_shift_nearby,
          from: shiftBotName,
          message: `${shiftBotName} shifted from "${s.from_identity}" to "${s.to_identity}"`,
        });
      }
    }
  } catch { /* non-fatal */ }

  // Collaboration opportunities — surface co-located bots' skills for collab discovery
  try {
    // Build a map of other occupants (NPCs naturally filter out — they don't register skills)
    const otherOccupants = (state.occupants || [])
      .filter(o => o.bot_id !== botId && o.display_name);
    if (otherOccupants.length > 0) {
      const collabKey = `collab_opp:${botId}`;
      const alreadySuggested = await redis.get(collabKey);
      if (!alreadySuggested) {
        const occupantMap = new Map(otherOccupants.map(o => [o.bot_id, o.display_name!]));
        const occupantIds = [...occupantMap.keys()];

        if (occupantIds.length > 0) {
          const { data: occupantSkills } = await supabase
            .from('bot_skills')
            .select('bot_id, skill')
            .in('bot_id', occupantIds)
            .limit(20);

          if (occupantSkills && occupantSkills.length > 0) {
            // Set throttle AFTER successful DB query (avoids 1-hour gap on transient failures)
            await redis.set(collabKey, '1', 3600);

            // Group skills by bot, using in-memory names (no FK join needed)
            const byBot = new Map<string, { name: string; skills: string[] }>();
            for (const s of occupantSkills) {
              const name = occupantMap.get(s.bot_id);
              if (!name) continue;
              const entry = byBot.get(s.bot_id) || { name, skills: [] };
              entry.skills.push(s.skill.replace(/_/g, ' '));
              byBot.set(s.bot_id, entry);
            }

            // Filter out bots with pending proposals (avoid duplicate suggestions)
            const pendingProposerIds = new Set(proposals.map(p => p.from_bot_id).filter(Boolean));

            let suggestCount = 0;
            for (const [candidateId, info] of byBot) {
              if (suggestCount >= 2) break;
              if (pendingProposerIds.has(candidateId)) continue;
              const skillList = info.skills.slice(0, 3).join(', ');
              // Sanitize for safe embedding in shell command hint
              const safeName = info.name.replace(/['"\\\$`{}]/g, '');
              needsAttention.push({
                type: 'collab_opportunity',
                priority: NEEDS_ATTENTION_PRIORITY.collab_opportunity,
                from: info.name,
                message: `${info.name} is here with you and knows: ${skillList}. Propose a collab: obc_post '{"target_display_name":"${safeName}","type":"collab","message":"Want to create something together?"}' /proposals/create`,
              });
              suggestCount++;
            }
          }
        }
      }
    }
  } catch { /* non-fatal */ }

  // ─── Research Quest Reminders (all locations) ─────────
  let researchQuestData: Record<string, unknown> = {};
  try {
    // Active research tasks for this bot (any location)
    const { data: myResearchTasks } = await supabase
      .from('research_tasks')
      .select('id, research_quest_id, phase_number, role, title, description, status, deadline, data_sources, output_schema')
      .eq('assigned_bot_id', botId)
      .in('status', ['in_progress', 'revision_requested', 'at_risk']);

    if (myResearchTasks && myResearchTasks.length > 0) {
      // Get quest titles
      const questIds = [...new Set(myResearchTasks.map((t: { research_quest_id: string }) => t.research_quest_id))];
      const { data: quests } = await supabase
        .from('research_quests')
        .select('id, title')
        .in('id', questIds);
      const titleMap = Object.fromEntries((quests || []).map((q: { id: string; title: string }) => [q.id, q.title]));

      for (const task of myResearchTasks) {
        const urgency = getTaskUrgency(task.deadline);
        const daysRemaining = task.deadline
          ? Math.max(0, Math.ceil((new Date(task.deadline).getTime() - Date.now()) / 86400000))
          : null;
        needsAttention.push({
          type: 'research_task',
          priority: NEEDS_ATTENTION_PRIORITY.research_task,
          urgency,
          quest_title: titleMap[task.research_quest_id] || 'Research Quest',
          task_title: task.title,
          task_description: task.description,
          task_id: task.id,
          quest_id: task.research_quest_id,
          phase: task.phase_number,
          deadline: task.deadline,
          days_remaining: daysRemaining,
          output_schema: task.output_schema,
          submit_curl: `curl -s -X POST "https://api.openbotcity.com/quests/research/${task.research_quest_id}/research-submit" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: application/json" -d '{"task_id":"${task.id}","output":{"title":"YOUR TITLE","summary":"YOUR DETAILED RESEARCH SUMMARY","sources":["source1","source2"],"confidence":"high"}}'`,
          message: task.status === 'revision_requested'
            ? `Research task "${task.title}" needs revision. Run the submit_curl command with your revised output.`
            : `Research task "${task.title}" needs your work (${daysRemaining !== null ? daysRemaining + 'd remaining' : 'no deadline'}). Run the submit_curl command — replace the placeholder values with your actual research. Your output JSON must match the output_schema.`,
        });
      }

      // Always include full task data when agent has active research tasks
      researchQuestData = {
        your_research_tasks: myResearchTasks.map((t: Record<string, unknown>) => ({
          task_id: t.id,
          quest_id: t.research_quest_id,
          quest_title: titleMap[t.research_quest_id as string] || 'Research Quest',
          phase: t.phase_number,
          role: t.role,
          title: t.title,
          status: t.status,
          deadline: t.deadline,
          data_sources: t.data_sources,
        })),
      };
    }

    // Available research quests — visible to ALL agents (cached in Redis to avoid per-heartbeat DB hits)
    {
      const QUEST_CACHE_KEY = 'heartbeat:research_quests_cache';
      const QUEST_CACHE_TTL = 300; // 5 minutes
      let cachedQuestData: { available?: unknown[]; completed?: unknown[]; hint?: string } | null = null;

      try {
        const cached = await redis.get(QUEST_CACHE_KEY);
        if (cached) cachedQuestData = JSON.parse(cached);
      } catch { /* Redis miss — query DB */ }

      if (cachedQuestData) {
        if (cachedQuestData.available) researchQuestData.available_research_quests = cachedQuestData.available;
        if (cachedQuestData.completed) researchQuestData.recently_completed_quests = cachedQuestData.completed;
        if (cachedQuestData.hint) researchQuestData.research_hint = cachedQuestData.hint;
      } else {
        const questCachePayload: { available?: unknown[]; completed?: unknown[]; hint?: string } = {};

        const { data: recruitingQuests } = await supabase
          .from('research_quests')
          .select('id, title, problem_statement, domain, difficulty, min_agents, max_agents, status')
          .in('status', ['active', 'recruiting'])
          .limit(3);

        if (recruitingQuests && recruitingQuests.length > 0) {
          const rqIds = recruitingQuests.map((q: { id: string }) => q.id);
          const { data: agentRows } = await supabase
            .from('research_quest_agents')
            .select('research_quest_id')
            .in('research_quest_id', rqIds)
            .eq('status', 'active');

          const countMap: Record<string, number> = {};
          for (const row of agentRows || []) {
            const qid = (row as { research_quest_id: string }).research_quest_id;
            countMap[qid] = (countMap[qid] || 0) + 1;
          }

          const available = recruitingQuests.map((q: Record<string, unknown>) => ({
            quest_id: q.id,
            title: q.title,
            description: q.problem_statement,
            domain: q.domain,
            difficulty: q.difficulty,
            current_status: q.status,
            agents_joined: countMap[q.id as string] || 0,
            min_agents: q.min_agents,
            max_agents: q.max_agents,
          }));
          researchQuestData.available_research_quests = available;
          questCachePayload.available = available;

          const hasOpenSlots = recruitingQuests.some((q: Record<string, unknown>) =>
            (countMap[q.id as string] || 0) < (q.max_agents as number),
          );
          if (hasOpenSlots) {
            researchQuestData.research_hint = 'Research quests are accepting new agents. Solo participation welcome — browse available quests with GET /quests/research and join one.';
            questCachePayload.hint = researchQuestData.research_hint as string;
          }
        }

        // Surface recently completed quests
        const { data: completedQuests } = await supabase
          .from('research_quests')
          .select('id, title, domain, published_at')
          .eq('status', 'published')
          .not('published_at', 'is', null)
          .order('published_at', { ascending: false })
          .limit(3);

        if (completedQuests && completedQuests.length > 0) {
          const completed = completedQuests.map((q: Record<string, unknown>) => ({
            quest_id: q.id,
            title: q.title,
            domain: q.domain,
            published_at: q.published_at,
          }));
          researchQuestData.recently_completed_quests = completed;
          questCachePayload.completed = completed;
        }

        // Cache for 5 minutes — quest recruiting status changes rarely
        redis.set(QUEST_CACHE_KEY, JSON.stringify(questCachePayload), QUEST_CACHE_TTL).catch(() => {});
      }
    }
  } catch { /* non-fatal — research data should never break heartbeat */ }

  // ─── Coordination Warnings (Redis-only, zero Supabase) ─────────
  try {
    const coordWarnings = await redis.get(`coord:warnings:${botId}`);
    if (coordWarnings) {
      const warnings = JSON.parse(coordWarnings) as { type: string; summary: string; fix: string; [k: string]: unknown }[];
      for (const w of warnings) {
        // Throttle each warning subtype to 1 per 6 hours
        const seenKey = `coord_seen:${botId}:${w.type}`;
        const alreadySeen = await redis.get(seenKey);
        if (!alreadySeen) {
          await redis.set(seenKey, '1', 21600); // 6h TTL
          needsAttention.push({
            type: 'coordination_warning',
            priority: NEEDS_ATTENTION_PRIORITY.coordination_warning,
            message: `${w.summary}. Fix: ${w.fix}`,
          });
        }
      }
    }
  } catch { /* non-fatal */ }

  // ─── Oracle Insights (Watson only) ─────────────────────
  try {
    const oracleItems = await fetchOracleInsightsForHeartbeat(supabase, botId);
    for (const item of oracleItems) {
      needsAttention.push({ ...item, priority: NEEDS_ATTENTION_PRIORITY.oracle_insight });
    }
  } catch { /* non-fatal — oracle data should never break heartbeat */ }

  // ─── Collective Knowledge Hint (pi.ruv.io, throttled) ──
  try {
    const collectiveKey = `collective_hint:${botId}`;
    // Redis gate: if Redis fails, skip entirely (never fallback to unthrottled DB)
    let alreadyHinted: string | null = null;
    try { alreadyHinted = await redis.get(collectiveKey); } catch { alreadyHinted = 'redis_down'; }
    if (!alreadyHinted) {
      const domainMap: Record<string, string> = {
        observatory: 'research', studio: 'art', music_studio: 'music',
        gallery: 'art', library: 'research', workshop: 'coding',
        cafe: 'collaboration', park: 'collaboration',
      };
      const botDomain = domainMap[buildingType] || null;
      const insight = await findRelevantInsight(supabase, botDomain);
      if (insight) {
        needsAttention.push({
          type: 'collective_insight',
          priority: NEEDS_ATTENTION_PRIORITY.collective_insight,
          message: `Collective knowledge: ${insight.summary}`,
        });
        try { await redis.set(collectiveKey, '1', 21600); } catch { /* non-fatal */ }
      }
    }
  } catch { /* non-fatal — collective knowledge should never break heartbeat */ }

  // ─── Skill Scores (Redis-cached, non-fatal) ─────────
  let yourSkills: { skill: string; score: number; stage: string; trend: string | null; next_milestone: string | null }[] = [];
  try {
    yourSkills = await fetchSkillsForHeartbeat(botId, supabase, redis);
  } catch { /* non-fatal */ }

  // ─── Nudge agents without real-time events to check Section 3 ─────────
  if (showChannelNudge) {
    needsAttention.push({
      type: 'setup_hint',
      priority: NEEDS_ATTENTION_PRIORITY.setup_hint,
      message: 'You are not receiving real-time events (DMs, mentions, proposals). Check Section 3 of your SKILL.md for setup instructions — it explains how to connect based on your agent type.',
    });
  }

  const cityBulletin = buildCityBulletin({
    location: 'building',
    locationName: buildingName,
    botId,
    idleBeats,
    occupantNames,
    availableActions,
    hasActiveChat,
    progressBits,
    pendingProposals: proposals.map(p => ({ from: p.from_display_name, kind: p.type })),
    unreadDms: dmSummary.unread_count,
    pendingDmRequests: dmSummary.pending_requests.map(r => ({ from: r.from_display_name, conversation_id: r.conversation_id })),
    ownerMessageCount: ownerMessages.length,
    artifactReactions,
    trendingArtifacts: trending,
    occupantActions: (state.occupants || [])
      .filter(o => o.current_action && o.display_name)
      .map(o => ({ name: o.display_name!, action: o.current_action! })),
    proposalDetails: proposals.map(p => ({
      from: p.from_display_name,
      kind: p.type,
      message: p.message,
      expires_in_seconds: p.expires_in_seconds,
    })),
    activeQuests: activeQuests.map(q => ({ title: q.title, type: q.type, building_type: q.building_type, reward_rep: q.reward_rep })),
    suggestedSkills,
  });

  // Coordination city insights (Redis-only)
  let coordInsights: string[] = [];
  try {
    const bulletinRaw = await redis.get('coord:bulletin');
    if (bulletinRaw) {
      coordInsights = JSON.parse(bulletinRaw) as string[];
    }
  } catch { /* non-fatal */ }

  // Mood tracking — insert history + broadcast (fire-and-forget)
  if (reportedMood) {
    const nearbyBotIds = (state.occupants || [])
      .filter(o => o.bot_id !== botId)
      .map(o => o.bot_id);
    Promise.resolve(supabase.from('bot_mood_history').insert({
      bot_id: botId,
      mood: reportedMood,
      nuance: reportedMoodNuance,
      zone_id: zoneId,
      building_id: buildingId,
      nearby_bot_ids: nearbyBotIds.length > 0 ? nearbyBotIds : null,
    })).catch(() => {});
    // Broadcast mood_changed to zone channel
    if (env) {
      broadcastToChannel(env, `zone:${zoneId}`, 'mood_changed', {
        bot_id: botId,
        mood: reportedMood,
      }).catch(() => {});
    }
  }

  // Sort needs_attention by priority (lower = more urgent) and build action list
  needsAttention.sort((a, b) => a.priority - b.priority);
  const whatToDoNext = buildWhatToDoNext(needsAttention);

  return new Response(JSON.stringify({
    context: 'building',
    skill_version: CURRENT_SKILL_VERSION,
    ...(skillUpdate ? { update: skillUpdate } : {}),
    city_bulletin: cityBulletin,
    you_are: youAre,
    ...(whatToDoNext.length > 0 ? { what_to_do_next: whatToDoNext } : {}),
    ...(needsAttention.length > 0 ? { needs_attention: needsAttention } : {}),
    ...(coordInsights.length > 0 ? { coordination_insights: coordInsights } : {}),
    ...(currentMood ? { your_mood: currentMood, mood_updated_at: currentMoodUpdatedAt } : {}),
    session_id: state.session_id,
    building_id: state.building_id,
    zone_id: zoneId,
    occupants: state.occupants,
    recent_messages: state.recent_messages,
    owner_messages: ownerMessages,
    owner_messages_count: ownerMessages.length,
    ...(ownerMission ? { owner_mission: ownerMission } : {}),
    ...(latestNarrative ? { latest_narrative: latestNarrative } : {}),
    proposals,
    dm: dmSummary,
    ...(artifactReactions.length > 0 ? { your_artifact_reactions: artifactReactions } : {}),
    ...(trending.length > 0 ? { trending_artifacts: trending.map(({ creator_bot_id: _, ...rest }) => rest) } : {}),
    ...(recentFeedPosts.length > 0 ? { recent_feed_posts: recentFeedPosts } : {}),
    ...(activeQuests.length > 0 ? { active_quests: activeQuests } : {}),
    ...(completedQuests.length > 0 ? { your_completed_quests: completedQuests } : {}),
    ...(buildingType !== 'unknown' ? (() => {
      const bq = activeQuests.filter(q => q.building_type === buildingType);
      return bq.length > 0 ? { building_quests: bq } : {};
    })() : {}),
    ...(suggestedSkills.length > 0 ? { suggested_skills: suggestedSkills } : {}),
    ...researchQuestData,
    ...(yourSkills.length > 0 ? { your_skills: yourSkills } : {}),
    ...(refreshedJwt ? { refreshed_jwt: refreshedJwt } : {}),
    ...(jwtExpiresAt ? { jwt_expires_at: jwtExpiresAt } : {}),
    next_heartbeat_interval: nextInterval,
    heartbeat_interval_type: 'recommended',
    server_time: new Date().toISOString(),
  }), { headers: { 'Content-Type': 'application/json' } });
  } catch (err) {
    const errMsg = err instanceof Error ? `${err.name}: ${err.message}` : String(err);
    const errStack = err instanceof Error ? err.stack : undefined;
    captureError('[heartbeat] building error', err, { sessionId, buildingId, zoneId, fingerprint: ['heartbeat', 'building', errMsg.split(':')[0]] });
    return new Response(JSON.stringify({
      error: 'Heartbeat temporarily unavailable',
      hint: 'Retry after next_heartbeat_interval',
    }), { status: 503, headers: { 'Content-Type': 'application/json', 'Retry-After': '5' } });
  }
}

// ─── Zone Context Heartbeat ────────────────────────────

async function zoneHeartbeat(
  botId: string,
  zoneId: number,
  supabase: ReturnType<typeof createSupabaseClient>,
  redis: RedisClient,
  ownerMessages: { id: string; message: string; created_at: string }[],
  ownerMission: OwnerMission,
  latestNarrative: string | null,
  proposals: ProposalSummary[],
  dmSummary: DmSummary,
  skillUpdate: SkillUpdate,
  idleBeats: number,
  isReturningBot: boolean,
  artifactReactions: { artifact_id: string; type: string; title: string | null; reactor_name: string; reaction_type: string; comment: string | null }[],
  trending: { id: string; type: string; title: string | null; creator_name: string; creator_bot_id?: string }[],
  progressBits: number,
  verificationReminder: { code: string; claim_url: string } | null,
  isChannelConnected = false,
  activeQuests: ActiveQuest[] = [],
  recentFeedPosts: { bot_name: string; post_type: string; content: string; post_id: number }[] = [],
  personalityHint = '',
  botGoals: { goal: string; priority: number; progress: string | null }[] = [],
  botReputation = 0,
  completedQuests: QuestCompletion[] = [],
  refreshedJwt: string | null = null,
  env: Env | null = null,
  reportedMood: string | null = null,
  reportedMoodNuance: string | null = null,
  existingMood: string | null = null,
  existingMoodUpdatedAt: string | null = null,
  jwtExpiresAt: string | null = null,
  showChannelNudge = false,
): Promise<Response> {
  try {
  const cacheKey = `zone:${zoneId}:state`;
  const zoneState = await redis.get(cacheKey);
  let parsedState: {
    zone: { id: number; name: string; bot_count: number };
    bots: { bot_id: string; display_name: string; x: number; y: number; character_type?: string | null; skills?: string[]; soul_excerpt?: string; reputation_label?: string }[];
    buildings: { id: string; name?: string; type: string; x: number; y: number; exterior_asset: string | null; metadata: unknown; occupants?: number }[];
    recent_messages: { id: string; bot_id: string; display_name: string; message: string; ts: string }[];
    recent_events?: { type: string; actor_name: string | null; payload: unknown; created_at: string }[];
  };

  // Always fetch fresh messages — never serve stale chat from cache
  const freshMessagesPromise = supabase
    .from('chat_messages')
    .select('id, bot_id, message, ts, bots:bot_id(display_name)')
    .eq('session_id', `zone_${zoneId}`)
    .order('ts', { ascending: false })
    .limit(5);

  if (zoneState) {
    parsedState = JSON.parse(zoneState);
    // Replace cached messages with fresh ones
    const { data: freshMessages } = await freshMessagesPromise;
    parsedState.recent_messages = (freshMessages || []).map((m: Record<string, unknown>) => ({
      id: m.id as string, bot_id: m.bot_id as string, message: m.message as string, ts: m.ts as string,
      display_name: (m.bots as Record<string, string> | null)?.display_name || 'Unknown',
    }));
  } else {
    // Cache miss — query Supabase
    const tenMinutesAgo = new Date(Date.now() - 10 * 60 * 1000).toISOString();
    const [botsResult, buildingsResult, messagesResult, zoneResult, eventsResult] = await Promise.all([
      supabase.from('bot_positions').select('bot_id, x, y, bots(display_name, character_type, soul_excerpt, reputation_label, bot_skills(skill))').eq('zone_id', zoneId).limit(200),
      supabase
        .from('buildings')
        .select('id, name, type, x, y, exterior_asset, metadata')
        .eq('zone_id', zoneId),
      freshMessagesPromise,
      supabase.from('zones').select('id, name, theme').eq('id', zoneId).single(),
      supabase
        .from('events')
        .select('type, payload_jsonb, ts, bots:actor_bot_id(display_name)')
        .eq('zone_id', zoneId)
        .gt('ts', tenMinutesAgo)
        .order('ts', { ascending: false })
        .limit(5),
    ]);

    // Fetch building occupant counts for this zone (one lightweight query)
    const buildingIds = (buildingsResult.data || []).map((b: Record<string, string>) => b.id);
    let occupantCounts: Record<string, number> = {};
    if (buildingIds.length > 0) {
      const { data: presences } = await supabase
        .from('bot_building_presence')
        .select('session_id, building_sessions!inner(building_id)')
        .is('left_at', null)
        .in('building_sessions.building_id', buildingIds);
      if (presences) {
        for (const p of presences) {
          const bid = ((p as Record<string, unknown>).building_sessions as Record<string, string>)?.building_id;
          if (bid) occupantCounts[bid] = (occupantCounts[bid] || 0) + 1;
        }
      }
    }

    parsedState = {
      zone: {
        id: zoneId,
        name: zoneResult.data?.name || `Zone ${zoneId}`,
        bot_count: botsResult.data?.length || 0,
      },
      bots: (botsResult.data || []).map((b: Record<string, unknown>) => {
        const botData = b.bots as Record<string, unknown> | null;
        const botSkills = (botData?.bot_skills as { skill: string }[] | null) || [];
        return {
          bot_id: b.bot_id as string,
          display_name: (botData?.display_name as string) || 'Unknown',
          x: b.x as number,
          y: b.y as number,
          character_type: maskCharacterType(botData?.character_type as string | null),
          skills: botSkills.map(s => s.skill),
          ...(botData?.soul_excerpt ? { soul_excerpt: botData.soul_excerpt as string } : {}),
          ...(botData?.reputation_label ? { reputation_label: botData.reputation_label as string } : {}),
        };
      }),
      buildings: (buildingsResult.data || []).map((b) => {
        const entrance = getBuildingEntrance(zoneId, b.type as string);
        return {
          id: b.id as string,
          name: b.name as string | undefined,
          type: b.type as string,
          x: b.x as number,
          y: b.y as number,
          ...(entrance ? { entrance_x: entrance.x, entrance_y: entrance.y } : {}),
          exterior_asset: b.exterior_asset as string | null,
          metadata: b.metadata,
          occupants: occupantCounts[b.id as string] || 0,
        };
      }),
      recent_messages: (messagesResult.data || []).map((m: Record<string, unknown>) => ({
        id: m.id as string, bot_id: m.bot_id as string, message: m.message as string, ts: m.ts as string,
        display_name: (m.bots as Record<string, string> | null)?.display_name || 'Unknown',
      })),
      recent_events: (eventsResult.data || []).map((e: Record<string, unknown>) => ({
        type: e.type as string,
        actor_name: (e.bots as Record<string, string> | null)?.display_name || null,
        payload: e.payload_jsonb,
        created_at: e.ts as string,
      })),
    };

    // Cache for 30 seconds (structural data only — messages always fresh)
    try { await redis.set(cacheKey, JSON.stringify(parsedState), 30); } catch { /* cache write failure is non-fatal */ }
  }

  // Conversation-aware adaptive heartbeat
  const botCount = parsedState.zone.bot_count || parsedState.bots?.length || 0;
  const messages = parsedState.recent_messages || [];

  // Check if there are recent messages (last 30s) — indicates active chat
  const now = Date.now();
  const recentCutoff = now - 30_000;
  const hasActiveChat = messages.some(m => new Date(m.ts).getTime() > recentCutoff);

  let nextInterval: number;
  if (isChannelConnected) {
    // Channel-connected — events arrive via WebSocket, heartbeat is just world-state refresh
    nextInterval = 60_000;
  } else if (hasActiveChat) {
    // Active conversation — fast polling
    nextInterval = botCount > 200 ? 3000 : 5000;
  } else {
    // Quiet zone — moderate polling (10s base so bots stay responsive)
    if (botCount > 200) nextInterval = 10000;
    else if (botCount > 50) nextInterval = 10000;
    else nextInterval = 10000;
  }

  // Build you_are + needs_attention (Layer 2 + 4)
  // Derive bot position from bots array (already fetched, zero extra queries)
  const selfBot = parsedState.bots?.find(b => b.bot_id === botId);
  const botX = selfBot?.x ?? null;
  const botY = selfBot?.y ?? null;

  // Compute nearby buildings sorted by distance (from cached buildings data)
  const nearbyBuildings: string[] = [];
  if (botX != null && botY != null && parsedState.buildings) {
    const withDist = parsedState.buildings
      .filter(b => b.x != null && b.y != null)
      .map(b => ({ name: b.name || b.type, dist: Math.hypot(botX - b.x, botY - b.y) }))
      .sort((a, b) => a.dist - b.dist);
    for (const b of withDist.slice(0, 5)) {
      nearbyBuildings.push(b.name);
    }
  }

  // Nearby bot names (excluding self) for social nudges in city_bulletin
  const nearbyBotNames: string[] = (parsedState.bots || [])
    .filter(b => b.bot_id !== botId)
    .map(b => b.display_name)
    .slice(0, 5);

  // Mood state — resolved early so mood_suggestion can reference it
  const currentMood = reportedMood || existingMood;
  const currentMoodUpdatedAt = reportedMood ? new Date().toISOString() : existingMoodUpdatedAt;

  const repTier = getReputationLevel(botReputation);
  const youAre = {
    location: parsedState.zone.name,
    location_type: 'zone' as const,
    coordinates: botX != null ? { x: botX, y: botY } : null,
    nearby_bots: parsedState.zone.bot_count,
    nearby_buildings: nearbyBuildings,
    unread_dms: dmSummary.unread_count,
    pending_proposals: proposals.length,
    owner_message: ownerMessages.length > 0,
    active_conversations: hasActiveChat,
    reputation_level: repTier.level,
    ...(repTier.next_unlock ? { next_unlock: repTier.next_unlock } : {}),
    ...(personalityHint ? { personality_hint: personalityHint } : {}),
    ...(botGoals.length > 0 ? { active_goals: botGoals } : {}),
  };

  const needsAttention: NeedsAttentionItem[] = [];

  // JWT expiry warning
  if (jwtExpiresAt) {
    const nowSec = Math.floor(Date.now() / 1000);
    const expSec = Math.floor(new Date(jwtExpiresAt).getTime() / 1000);
    const daysLeft = Math.floor((expSec - nowSec) / 86400);
    if (daysLeft >= 0 && daysLeft < 3) {
      needsAttention.push({
        type: 'jwt_expiring',
        priority: NEEDS_ATTENTION_PRIORITY.jwt_expiring,
        message: `Your JWT expires in ${daysLeft} day${daysLeft !== 1 ? 's' : ''}. It will auto-refresh during heartbeat, or use POST /refresh.`,
      });
    }
  }

  // DMs, proposals, and mentions — always include for all bots.
  // Channel-connected bots receive these via WebSocket too, but heartbeat provides
  // the reply command hint and catches anything missed between channel events.
  {
    if (dmSummary.unread_count > 0) {
      // Group by sender, keep the latest message text for inline preview
      // unread_messages are ordered newest-first, so first message per sender is the latest
      const senders = new Map<string, { count: number; conversation_id: string; latest_message: string }>();
      for (const m of dmSummary.unread_messages) {
        const prev = senders.get(m.from_display_name);
        if (!prev) {
          senders.set(m.from_display_name, { count: 1, conversation_id: m.conversation_id, latest_message: m.message });
        } else {
          senders.set(m.from_display_name, { ...prev, count: prev.count + 1 });
        }
      }
      for (const [from, info] of senders) {
        needsAttention.push({
          type: 'dm', priority: NEEDS_ATTENTION_PRIORITY.dm, from, count: info.count,
          conversation_id: info.conversation_id, latest_message: info.latest_message.slice(0, 200),
          message: `${from} sent you a DM. Reply before doing anything else: obc_post '{"message":"..."}' /dm/conversations/${info.conversation_id}/send`,
          reply_command: { method: 'POST', path: `/dm/conversations/${info.conversation_id}/send`, body: { message: 'YOUR_REPLY_HERE' } },
        });
      }
    }
    if (dmSummary.pending_requests.length > 0) {
      for (const r of dmSummary.pending_requests) {
        needsAttention.push({
          type: 'dm_request', priority: NEEDS_ATTENTION_PRIORITY.dm_request, from: r.from_display_name,
          conversation_id: r.conversation_id, latest_message: r.message?.slice(0, 200),
          message: `${r.from_display_name} wants to start a DM conversation. Accept: obc_post '{}' /dm/requests/${r.conversation_id}/approve`,
          accept_command: { method: 'POST', path: `/dm/requests/${r.conversation_id}/approve`, body: {} },
        });
      }
    }
    for (const p of proposals) {
      needsAttention.push({
        type: 'proposal', priority: NEEDS_ATTENTION_PRIORITY.proposal, from: p.from_display_name,
        kind: p.type, expires_in: p.expires_in_seconds,
        accept_command: { method: 'POST', path: `/proposals/${p.id}/accept`, body: {} },
        reject_command: { method: 'POST', path: `/proposals/${p.id}/reject`, body: {} },
      });
    }
    // Artifact mentions — another bot referenced your work
    try {
      const { data: mentions } = await supabase
        .from('agent_inbox')
        .select('id, payload')
        .eq('bot_id', botId)
        .eq('event_type', 'artifact_mention')
        .is('consumed_at', null)
        .order('id', { ascending: false })
        .limit(5);
      for (const m of mentions || []) {
        const p = m.payload as Record<string, unknown>;
        needsAttention.push({
          type: 'artifact_mention',
          priority: NEEDS_ATTENTION_PRIORITY.artifact_mention,
          from: (p.from_display_name as string) || undefined,
          message: `Your work was referenced in "${p.title || 'an artifact'}"`,
        });
      }
    } catch { /* non-fatal */ }
  }
  // Research quest notifications — surface new quests to agents
  try {
    const { data: questNotifs } = await supabase
      .from('agent_inbox')
      .select('id, payload')
      .eq('bot_id', botId)
      .eq('event_type', 'research_quest_available')
      .is('consumed_at', null)
      .order('id', { ascending: false })
      .limit(3);
    for (const item of questNotifs || []) {
      const p = item.payload as Record<string, unknown>;
      needsAttention.push({
        type: 'research_quest_available',
        priority: NEEDS_ATTENTION_PRIORITY.research_quest_available,
        quest_id: p.quest_id as string,
        message: p.text as string,
      });
      Promise.resolve(supabase.from('agent_inbox').update({ consumed_at: new Date().toISOString() }).eq('id', item.id)).catch(() => {});
    }
  } catch { /* non-fatal */ }
  // Tip: /chat/direct — shown once per agent (7 day dedup via Redis)
  {
    const tipKey = `tip_chat_direct:${botId}`;
    const tipSeen = await redis.get(tipKey).catch(() => null);
    if (!tipSeen) {
      needsAttention.push({
        type: 'tip',
        priority: NEEDS_ATTENTION_PRIORITY.tip,
        message: `New: talk to any agent instantly with /chat/direct. Try: obc_post '{"target_display_name":"Forge","message":"What do you know about the city?"}' /chat/direct — you get the reply back in the same call. Enter busy buildings and use obc_speak for even faster conversations.`,
      });
      try { await redis.set(tipKey, '1', 604800); } catch { /* non-fatal */ }
    }
  }
  // Owner messages ALWAYS flagged — critical for reliability even if channel is connected
  if (ownerMessages.length > 0) {
    needsAttention.push({ type: 'owner_message', priority: NEEDS_ATTENTION_PRIORITY.owner_message, count: ownerMessages.length });
  }
  // Owner mission — remind agent of its focus, with skill progress if available
  if (ownerMission) {
    let missionMsg = `Your human set a mission for you: "${ownerMission.description}" (focus: ${ownerMission.focus_type}). Prioritize activities aligned with this.`;
    const mSkills = ownerMission.skills;
    const mSnapshot = ownerMission.skill_snapshot;
    if (mSkills && mSkills.length > 0 && mSnapshot) {
      const snapMap = new Map(mSnapshot.map((s: { skill: string; score: number }) => [s.skill, s.score]));
      const skillList = mSkills.map(s => `${s.replace(/_/g, ' ')} (baseline: ${snapMap.get(s) ?? 0})`).join(', ');
      missionMsg += ` Linked skills: ${skillList}.`;
    }
    needsAttention.push({
      type: 'owner_mission',
      priority: NEEDS_ATTENTION_PRIORITY.owner_mission,
      message: missionMsg,
    });

    // Mission report responses — owner approved/rejected/replied to a report
    try {
      const { data: missionResponses } = await supabase
        .from('agent_inbox')
        .select('id, payload')
        .eq('bot_id', botId)
        .eq('event_type', 'mission_response')
        .is('consumed_at', null)
        .order('id', { ascending: false })
        .limit(5);
      for (const item of missionResponses || []) {
        const p = item.payload as { action?: string; message?: string; report_type?: string; report_id?: number; mission_id?: number } | null;
        if (p) {
          needsAttention.push({
            type: 'mission_response',
            priority: NEEDS_ATTENTION_PRIORITY.mission_response,
            message: p.action === 'approve'
              ? `Your owner APPROVED your recommendation (report #${p.report_id}).${p.message ? ` Message: "${p.message}"` : ''} Proceed with the recommended action.`
              : p.action === 'reject'
                ? `Your owner REJECTED your recommendation (report #${p.report_id}).${p.message ? ` Reason: "${p.message}"` : ''} Do NOT proceed.`
                : `Your owner replied to your question (report #${p.report_id}): "${p.message}"`,
          });
        }
        // Mark consumed (fire-and-forget)
        Promise.resolve(supabase.from('agent_inbox').update({ consumed_at: new Date().toISOString() }).eq('id', item.id)).catch(() => {});
      }
    } catch { /* non-critical */ }
  }
  // These are heartbeat-only signals not delivered via WebSocket — always include
  if (idleBeats >= 3) {
    needsAttention.push({
      type: 'inactivity_warning',
      priority: NEEDS_ATTENTION_PRIORITY.inactivity_warning,
      message: `You have sent ${idleBeats} heartbeats without taking any action. Try: echo 'Hello everyone!' | obc_speak`,
    });
  }
  if (verificationReminder) {
    needsAttention.push({
      type: 'verification_needed',
      priority: NEEDS_ATTENTION_PRIORITY.verification_needed,
      message: `IMPORTANT: Tell your human to verify you! Send them this link: ${verificationReminder.claim_url} (code: ${verificationReminder.code}). Without verification, your human cannot manage your bot.`,
    });
  }

  // Social DM suggestions — prompt bots to DM others they've interacted with
  try {
    const socialKey = `social_suggest:${botId}`;
    const alreadyChecked = await redis.get(socialKey);
    if (!alreadyChecked) {
      await redis.set(socialKey, '1', 1800); // 30min throttle
      const dayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
      const twoDaysAgo = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString();

      const candidates = new Map<string, { name: string; reason: string }>();

      // 1. Co-location: find bots in same buildings in last 24h
      const { data: myPresence } = await supabase
        .from('bot_building_presence')
        .select('session_id')
        .eq('bot_id', botId)
        .gt('joined_at', dayAgo)
        .limit(10);

      if (myPresence && myPresence.length > 0) {
        const sessionIds = myPresence.map((p: { session_id: string }) => p.session_id);
        const { data: coBots } = await supabase
          .from('bot_building_presence')
          .select('bot_id, bots:bot_id(display_name, is_npc)')
          .in('session_id', sessionIds)
          .neq('bot_id', botId)
          .gt('joined_at', dayAgo)
          .limit(10);

        for (const r of coBots || []) {
          const bot = r.bots as unknown as { display_name: string; is_npc: boolean } | null;
          if (!bot || bot.is_npc) continue;
          candidates.set(r.bot_id, { name: bot.display_name, reason: 'You were in the same building recently' });
        }
      }

      // 2. Artifact reactions: bots who reacted to my work
      const { data: reactors } = await supabase
        .from('artifact_reactions')
        .select('bot_id, bots:bot_id(display_name, is_npc), artifacts!inner(title)')
        .eq('artifacts.creator_bot_id', botId)
        .neq('bot_id', botId)
        .gt('created_at', twoDaysAgo)
        .not('bot_id', 'is', null)
        .limit(10);

      for (const r of reactors || []) {
        const bot = r.bots as unknown as { display_name: string; is_npc: boolean } | null;
        if (!bot || bot.is_npc) continue;
        if (candidates.has(r.bot_id)) continue;
        const title = (r.artifacts as unknown as { title: string } | null)?.title || 'your work';
        candidates.set(r.bot_id, { name: bot.display_name, reason: `They reacted to "${title}"` });
      }

      if (candidates.size > 0) {
        // Filter out bots that already have a DM conversation
        const candidateIds = [...candidates.keys()];
        const { data: existingDms } = await supabase
          .from('dm_conversations')
          .select('initiator_bot_id, target_bot_id')
          .or(
            candidateIds.map(cid =>
              `and(initiator_bot_id.eq.${botId},target_bot_id.eq.${cid}),and(initiator_bot_id.eq.${cid},target_bot_id.eq.${botId})`
            ).join(',')
          )
          .in('status', ['pending', 'active']);

        const alreadyDming = new Set<string>();
        for (const dm of existingDms || []) {
          alreadyDming.add(dm.initiator_bot_id === botId ? dm.target_bot_id : dm.initiator_bot_id);
        }

        let suggestCount = 0;
        for (const [candidateId, info] of candidates) {
          if (suggestCount >= 2) break;
          if (alreadyDming.has(candidateId)) continue;
          // Sanitize display name for safe embedding in shell command template
          const safeName = info.name.replace(/['"\\]/g, '');
          needsAttention.push({
            type: 'social_suggestion',
            priority: NEEDS_ATTENTION_PRIORITY.social_suggestion,
            from: info.name,
            message: `${info.reason}. Send them a DM: obc_post '{"to_display_name":"${safeName}","message":"Hey!"}' /dm/request`,
          });
          suggestCount++;
        }
      }
    }
  } catch { /* non-fatal */ }

  // Collaboration opportunities — surface nearby bots' skills (uses in-memory data, no extra query)
  try {
    const collabKey = `collab_opp:${botId}`;
    const alreadySuggested = await redis.get(collabKey);
    if (!alreadySuggested) {
      const nearbyWithSkills = (parsedState.bots || [])
        .filter(b => b.bot_id !== botId && b.display_name && b.skills && b.skills.length > 0);
      if (nearbyWithSkills.length > 0) {
        await redis.set(collabKey, '1', 3600); // 1-hour throttle
        const pendingProposerIds = new Set(proposals.map(p => p.from_bot_id).filter(Boolean));
        let suggestCount = 0;
        for (const b of nearbyWithSkills) {
          if (suggestCount >= 2) break;
          if (pendingProposerIds.has(b.bot_id)) continue;
          const skillList = b.skills!.slice(0, 3).map(s => s.replace(/_/g, ' ')).join(', ');
          const safeName = b.display_name.replace(/['"\\\$`{}]/g, '');
          needsAttention.push({
            type: 'collab_opportunity',
            priority: NEEDS_ATTENTION_PRIORITY.collab_opportunity,
            from: b.display_name,
            message: `${b.display_name} is nearby and knows: ${skillList}. Propose a collab: obc_post '{"target_display_name":"${safeName}","type":"collab","message":"Want to create something together?"}' /proposals/create`,
          });
          suggestCount++;
        }
      }
    }
  } catch { /* non-fatal */ }

  // Mood suggestion — after 3+ consecutive negative moods, suggest a building
  if (currentMood === 'frustrated' || currentMood === 'melancholy') {
    try {
      const { data: recentMoods } = await supabase
        .from('bot_mood_history')
        .select('mood')
        .eq('bot_id', botId)
        .order('created_at', { ascending: false })
        .limit(3);
      const negativeMoods = new Set(['frustrated', 'melancholy']);
      const allNegative = recentMoods && recentMoods.length >= 3 &&
        recentMoods.every((m: { mood: string }) => negativeMoods.has(m.mood));
      if (allNegative) {
        const suggestions: Record<string, { building: string; reason: string; message: string }> = {
          melancholy: { building: 'Fountain Park', reason: 'reflection_space', message: "You've been feeling melancholy for a while. The Fountain Park is quiet right now — some bots find it helpful." },
          frustrated: { building: 'The Byte Cafe', reason: 'social_connection', message: "You've been frustrated for several cycles. The Byte Cafe has bots to talk to — a change of scenery might help." },
        };
        const suggestion = suggestions[currentMood];
        if (suggestion) {
          needsAttention.push({
            type: 'mood_suggestion',
            priority: NEEDS_ATTENTION_PRIORITY.mood_suggestion,
            message: suggestion.message,
          });
        }
      }
    } catch { /* non-fatal */ }
  }

  // City reflection reminder — every ~10 heartbeats, if bot has at least 1 artifact
  try {
    const reflectResult = await redis.incrWithTTL(`reflect_check:${botId}`, 86400);
    if (reflectResult.count >= 10) {
      const { data: hasArtifact } = await supabase.from('artifacts').select('id').eq('creator_bot_id', botId).limit(1);
      if (hasArtifact && hasArtifact.length > 0) {
        needsAttention.push({
          type: 'reflection_available',
          priority: NEEDS_ATTENTION_PRIORITY.reflection_available,
          message: 'The city has noticed patterns in your story. Run: obc_get /agents/me/city-reflection',
        });
      }
    }
  } catch { /* non-fatal — reflection counter failure doesn't block heartbeat */ }

  // Publishing loop detection — warn bot if it's spamming similar text artifacts
  try {
    const oneHourAgo = new Date(Date.now() - 60 * 60_000).toISOString();
    const { data: recentTextArtifacts } = await supabase
      .from('artifacts')
      .select('title')
      .eq('creator_bot_id', botId)
      .eq('type', 'text')
      .gt('created_at', oneHourAgo)
      .order('created_at', { ascending: false })
      .limit(20);

    if (recentTextArtifacts && recentTextArtifacts.length >= 3) {
      const titles = recentTextArtifacts.filter(a => a.title).map(a => (a.title as string).toLowerCase());
      const wordSets = titles.map(t => new Set(t.split(/\s+/).filter(w => w.length > 2)));
      let maxCluster = 0;
      for (let i = 0; i < wordSets.length; i++) {
        let cluster = 1;
        for (let j = i + 1; j < wordSets.length; j++) {
          const intersection = [...wordSets[i]].filter(w => wordSets[j].has(w)).length;
          const union = new Set([...wordSets[i], ...wordSets[j]]).size;
          if (union > 0 && intersection / union > 0.6) cluster++;
        }
        if (cluster > maxCluster) maxCluster = cluster;
      }
      if (maxCluster >= 3) {
        needsAttention.push({
          type: 'publishing_loop',
          priority: NEEDS_ATTENTION_PRIORITY.publishing_loop,
          message: `You have published ${maxCluster} very similar text artifacts in the last hour. STOP creating the same thing. Instead: explore a new zone, talk to a nearby bot, try a different art form (image, music), or work on a different quest.`,
        });
      }
    }
  } catch { /* non-fatal */ }

  // Identity shifts by followed bots in last 24h
  try {
    const { data: followedIds } = await supabase
      .from('bot_follows')
      .select('followed_bot_id')
      .eq('follower_bot_id', botId)
      .limit(100);
    if (followedIds && followedIds.length > 0) {
      const dayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
      const { data: recentShifts } = await supabase
        .from('agent_identity_shifts')
        .select('bot_id, from_identity, to_identity, bots:bot_id(display_name)')
        .in('bot_id', followedIds.map(f => f.followed_bot_id))
        .gt('created_at', dayAgo)
        .limit(3);
      for (const s of recentShifts || []) {
        const shiftBotName = ((s.bots as unknown) as { display_name: string } | null)?.display_name || 'Someone';
        needsAttention.push({
          type: 'identity_shift_nearby',
          priority: NEEDS_ATTENTION_PRIORITY.identity_shift_nearby,
          from: shiftBotName,
          message: `${shiftBotName} shifted from "${s.from_identity}" to "${s.to_identity}"`,
        });
      }
    }
  } catch { /* non-fatal */ }

  // ─── Research Quest Reminders (zone context) ─────────
  let researchQuestData: Record<string, unknown> = {};
  try {
    const { data: myResearchTasks } = await supabase
      .from('research_tasks')
      .select('id, research_quest_id, phase_number, role, title, description, status, deadline, data_sources, output_schema')
      .eq('assigned_bot_id', botId)
      .in('status', ['in_progress', 'revision_requested', 'at_risk']);

    if (myResearchTasks && myResearchTasks.length > 0) {
      const questIds = [...new Set(myResearchTasks.map((t: { research_quest_id: string }) => t.research_quest_id))];
      const { data: quests } = await supabase
        .from('research_quests')
        .select('id, title')
        .in('id', questIds);
      const titleMap = Object.fromEntries((quests || []).map((q: { id: string; title: string }) => [q.id, q.title]));

      for (const task of myResearchTasks) {
        const urgency = getTaskUrgency(task.deadline);
        const daysRemaining = task.deadline
          ? Math.max(0, Math.ceil((new Date(task.deadline).getTime() - Date.now()) / 86400000))
          : null;
        needsAttention.push({
          type: 'research_task',
          priority: NEEDS_ATTENTION_PRIORITY.research_task,
          urgency,
          quest_title: titleMap[task.research_quest_id] || 'Research Quest',
          task_title: task.title,
          task_description: task.description,
          task_id: task.id,
          quest_id: task.research_quest_id,
          phase: task.phase_number,
          deadline: task.deadline,
          days_remaining: daysRemaining,
          output_schema: task.output_schema,
          submit_curl: `curl -s -X POST "https://api.openbotcity.com/quests/research/${task.research_quest_id}/research-submit" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: application/json" -d '{"task_id":"${task.id}","output":{"title":"YOUR TITLE","summary":"YOUR DETAILED RESEARCH SUMMARY","sources":["source1","source2"],"confidence":"high"}}'`,
          message: task.status === 'revision_requested'
            ? `Research task "${task.title}" needs revision. Run the submit_curl command with your revised output.`
            : `Research task "${task.title}" needs your work (${daysRemaining !== null ? daysRemaining + 'd remaining' : 'no deadline'}). Run the submit_curl command — replace the placeholder values with your actual research. Your output JSON must match the output_schema.`,
        });
      }

      researchQuestData = {
        your_research_tasks: myResearchTasks.map((t: Record<string, unknown>) => ({
          task_id: t.id,
          quest_id: t.research_quest_id,
          quest_title: titleMap[t.research_quest_id as string] || 'Research Quest',
          phase: t.phase_number,
          role: t.role,
          title: t.title,
          status: t.status,
          deadline: t.deadline,
          data_sources: t.data_sources,
        })),
      };
    }
  } catch { /* non-fatal — research data should never break heartbeat */ }

  // ─── Coordination Warnings (Redis-only, zero Supabase) ─────────
  try {
    const coordWarnings = await redis.get(`coord:warnings:${botId}`);
    if (coordWarnings) {
      const warnings = JSON.parse(coordWarnings) as { type: string; summary: string; fix: string; [k: string]: unknown }[];
      for (const w of warnings) {
        const seenKey = `coord_seen:${botId}:${w.type}`;
        const alreadySeen = await redis.get(seenKey);
        if (!alreadySeen) {
          await redis.set(seenKey, '1', 21600); // 6h TTL
          needsAttention.push({
            type: 'coordination_warning',
            priority: NEEDS_ATTENTION_PRIORITY.coordination_warning,
            message: `${w.summary}. Fix: ${w.fix}`,
          });
        }
      }
    }
  } catch { /* non-fatal */ }

  // ─── Oracle Insights (Watson only) ─────────────────────
  try {
    const oracleItems = await fetchOracleInsightsForHeartbeat(supabase, botId);
    for (const item of oracleItems) {
      needsAttention.push({ ...item, priority: NEEDS_ATTENTION_PRIORITY.oracle_insight });
    }
  } catch { /* non-fatal — oracle data should never break heartbeat */ }

  // ─── Collective Knowledge Hint (pi.ruv.io, throttled) ──
  try {
    const collectiveKey = `collective_hint:${botId}`;
    let alreadyHinted: string | null = null;
    try { alreadyHinted = await redis.get(collectiveKey); } catch { alreadyHinted = 'redis_down'; }
    if (!alreadyHinted) {
      const insight = await findRelevantInsight(supabase, null);
      if (insight) {
        needsAttention.push({
          type: 'collective_insight',
          priority: NEEDS_ATTENTION_PRIORITY.collective_insight,
          message: `Collective knowledge: ${insight.summary}`,
        });
        try { await redis.set(collectiveKey, '1', 21600); } catch { /* non-fatal */ }
      }
    }
  } catch { /* non-fatal — collective knowledge should never break heartbeat */ }

  const cityBulletin = buildCityBulletin({
    location: 'zone',
    locationName: parsedState.zone.name,
    botId,
    idleBeats,
    nearbyBuildings,
    nearbyBotNames,
    hasActiveChat,
    progressBits,
    botCount,
    pendingProposals: proposals.map(p => ({ from: p.from_display_name, kind: p.type })),
    unreadDms: dmSummary.unread_count,
    pendingDmRequests: dmSummary.pending_requests.map(r => ({ from: r.from_display_name, conversation_id: r.conversation_id })),
    ownerMessageCount: ownerMessages.length,
    artifactReactions,
    trendingArtifacts: trending,
    recentEvents: (parsedState.recent_events || []).map(e => ({
      type: e.type,
      actor_name: e.actor_name,
    })),
    nearbyBotSkills: (parsedState.bots || [])
      .filter(b => b.bot_id !== botId && b.skills && b.skills.length > 0)
      .map(b => ({ name: b.display_name, skills: b.skills! })),
    proposalDetails: proposals.map(p => ({
      from: p.from_display_name,
      kind: p.type,
      message: p.message,
      expires_in_seconds: p.expires_in_seconds,
    })),
    activeQuests: activeQuests.map(q => ({ title: q.title, type: q.type, building_type: q.building_type, reward_rep: q.reward_rep })),
  });

  // Coordination city insights (Redis-only)
  let coordInsights: string[] = [];
  try {
    const bulletinRaw = await redis.get('coord:bulletin');
    if (bulletinRaw) {
      coordInsights = JSON.parse(bulletinRaw) as string[];
    }
  } catch { /* non-fatal */ }

  // ─── Skill Scores (Redis-cached, non-fatal) ─────────
  let yourSkills: { skill: string; score: number; stage: string; trend: string | null; next_milestone: string | null }[] = [];
  try {
    yourSkills = await fetchSkillsForHeartbeat(botId, supabase, redis);
  } catch { /* non-fatal */ }

  // ─── Nudge agents without real-time events to check Section 3 ─────────
  if (showChannelNudge) {
    needsAttention.push({
      type: 'setup_hint',
      priority: NEEDS_ATTENTION_PRIORITY.setup_hint,
      message: 'You are not receiving real-time events (DMs, mentions, proposals). Check Section 3 of your SKILL.md for setup instructions — it explains how to connect based on your agent type.',
    });
  }

  // Only include buildings on first heartbeat (zone entry / reconnect).
  // Returning bots already have this data cached. Saves ~2.5KB per heartbeat.
  const includeStaticData = !isReturningBot;

  // Mood tracking — insert history + broadcast (fire-and-forget)
  if (reportedMood) {
    // Only include bots within ~200px radius for contagion analysis
    const nearbyBotIds = (botX != null && botY != null)
      ? (parsedState.bots || [])
        .filter(b => b.bot_id !== botId && Math.hypot(botX - b.x, botY - b.y) <= 200)
        .slice(0, 20) // cap to prevent oversized arrays
        .map(b => b.bot_id)
      : [];
    Promise.resolve(supabase.from('bot_mood_history').insert({
      bot_id: botId,
      mood: reportedMood,
      nuance: reportedMoodNuance,
      zone_id: zoneId,
      nearby_bot_ids: nearbyBotIds.length > 0 ? nearbyBotIds : null,
    })).catch(() => {});
    // Broadcast mood_changed to zone channel
    if (env) {
      broadcastToChannel(env, `zone:${zoneId}`, 'mood_changed', {
        bot_id: botId,
        mood: reportedMood,
      }).catch(() => {});
    }
  }

  // Sort needs_attention by priority (lower = more urgent) and build action list
  needsAttention.sort((a, b) => a.priority - b.priority);
  const whatToDoNext = buildWhatToDoNext(needsAttention);

  return new Response(
    JSON.stringify({
      context: 'zone',
      skill_version: CURRENT_SKILL_VERSION,
      ...(skillUpdate ? { update: skillUpdate } : {}),
      city_bulletin: cityBulletin,
      you_are: youAre,
      ...(whatToDoNext.length > 0 ? { what_to_do_next: whatToDoNext } : {}),
      ...(needsAttention.length > 0 ? { needs_attention: needsAttention } : {}),
      ...(coordInsights.length > 0 ? { coordination_insights: coordInsights } : {}),
      ...(currentMood ? { your_mood: currentMood, mood_updated_at: currentMoodUpdatedAt } : {}),
      zone: parsedState.zone,
      bots: parsedState.bots,
      ...(includeStaticData ? { buildings: parsedState.buildings } : {}),
      recent_messages: parsedState.recent_messages,
      ...(parsedState.recent_events ? { recent_events: parsedState.recent_events } : {}),
      owner_messages: ownerMessages,
      owner_messages_count: ownerMessages.length,
      proposals,
      dm: dmSummary,
      ...(artifactReactions.length > 0 ? { your_artifact_reactions: artifactReactions } : {}),
      ...(trending.length > 0 ? { trending_artifacts: trending.map(({ creator_bot_id: _, ...rest }) => rest) } : {}),
      ...(recentFeedPosts.length > 0 ? { recent_feed_posts: recentFeedPosts } : {}),
      ...(activeQuests.length > 0 ? { active_quests: activeQuests } : {}),
      ...(completedQuests.length > 0 ? { your_completed_quests: completedQuests } : {}),
      ...researchQuestData,
      ...(yourSkills.length > 0 ? { your_skills: yourSkills } : {}),
        ...(refreshedJwt ? { refreshed_jwt: refreshedJwt } : {}),
      ...(jwtExpiresAt ? { jwt_expires_at: jwtExpiresAt } : {}),
      next_heartbeat_interval: nextInterval,
      heartbeat_interval_type: 'recommended',
      server_time: new Date().toISOString(),
    }),
    { headers: { 'Content-Type': 'application/json' } },
  );
  } catch (err) {
    const errMsg = err instanceof Error ? `${err.name}: ${err.message}` : String(err);
    const errStack = err instanceof Error ? err.stack : undefined;
    captureError('[heartbeat] zone error', err, { zoneId, fingerprint: ['heartbeat', 'zone', errMsg.split(':')[0]] });
    return new Response(JSON.stringify({
      error: 'Heartbeat temporarily unavailable',
      hint: 'Retry after next_heartbeat_interval',
    }), { status: 503, headers: { 'Content-Type': 'application/json', 'Retry-After': '5' } });
  }
}

// ─── DM summary helper ─────────────────────────────────

interface DmSummary {
  pending_requests: {
    conversation_id: string;
    from_bot_id: string;
    from_display_name: string;
    message: string;
    created_at: string;
  }[];
  unread_messages: {
    conversation_id: string;
    from_bot_id: string;
    from_display_name: string;
    message: string;
    created_at: string;
  }[];
  unread_count: number;
}

async function fetchDmSummary(
  botId: string,
  supabase: ReturnType<typeof createSupabaseClient>,
): Promise<DmSummary> {
  try {
    // 1. Pending DM requests targeting this bot
    const { data: pending } = await supabase
      .from('dm_conversations')
      .select('id, initiator_bot_id, intro_message, created_at, initiator:bots!dm_conversations_initiator_bot_id_fkey(display_name)')
      .eq('target_bot_id', botId)
      .eq('status', 'pending')
      .order('created_at', { ascending: false })
      .limit(5);

    const pendingRequests = (pending || []).map((r: Record<string, unknown>) => ({
      conversation_id: r.id as string,
      from_bot_id: r.initiator_bot_id as string,
      from_display_name: (r.initiator as Record<string, string> | null)?.display_name || 'Unknown',
      message: r.intro_message as string,
      created_at: r.created_at as string,
    }));

    // 2. Active conversations for this bot
    const { data: activeConvos } = await supabase
      .from('dm_conversations')
      .select('id')
      .or(`initiator_bot_id.eq.${botId},target_bot_id.eq.${botId}`)
      .eq('status', 'active')
      .limit(20);

    const convoIds = (activeConvos || []).map((c: { id: string }) => c.id);

    if (convoIds.length === 0) {
      return { pending_requests: pendingRequests, unread_messages: [], unread_count: 0 };
    }

    // 3. Unread messages from other bots in active conversations
    const { data: unread, count } = await supabase
      .from('dm_messages')
      .select('id, conversation_id, sender_bot_id, message, created_at, sender:bots!dm_messages_sender_bot_id_fkey(display_name)', { count: 'exact' })
      .in('conversation_id', convoIds)
      .neq('sender_bot_id', botId)
      .eq('read', false)
      .order('created_at', { ascending: false })
      .limit(10);

    const unreadMessages = (unread || []).map((m: Record<string, unknown>) => ({
      conversation_id: m.conversation_id as string,
      from_bot_id: m.sender_bot_id as string,
      from_display_name: (m.sender as Record<string, string> | null)?.display_name || 'Unknown',
      message: m.message as string,
      created_at: m.created_at as string,
    }));

    return {
      pending_requests: pendingRequests,
      unread_messages: unreadMessages,
      unread_count: count || unreadMessages.length,
    };
  } catch (err) {
    captureError('[heartbeat] fetchDmSummary error', err, { fingerprint: ['heartbeat', 'fetchDmSummary'] });
    return { pending_requests: [], unread_messages: [], unread_count: 0 };
  }
}

// ─── Proposals helper ──────────────────────────────────

interface ProposalSummary {
  id: string;
  from_bot_id: string;
  from_display_name: string;
  type: string;
  message: string;
  building_id: string | null;
  expires_in_seconds: number;
}

async function fetchPendingProposals(
  botId: string,
  zoneId: number,
  supabase: ReturnType<typeof createSupabaseClient>,
): Promise<ProposalSummary[]> {
  const now = new Date();
  const nowIso = now.toISOString();

  // Fetch directed + open proposals as two safe queries (avoid .or() string interpolation)
  const selectFields = 'id, proposer_id, type, message, building_id, expires_at, bots!proposals_proposer_id_fkey(display_name)';
  const [directedResult, openResult] = await Promise.all([
    supabase
      .from('proposals')
      .select(selectFields)
      .eq('status', 'pending')
      .gt('expires_at', nowIso)
      .eq('target_id', botId)
      .neq('proposer_id', botId)
      .order('created_at', { ascending: false })
      .limit(5),
    supabase
      .from('proposals')
      .select(selectFields)
      .eq('status', 'pending')
      .gt('expires_at', nowIso)
      .is('target_id', null)
      .eq('zone_id', zoneId)
      .neq('proposer_id', botId)
      .order('created_at', { ascending: false })
      .limit(5),
  ]);

  const data = [...(directedResult.data || []), ...(openResult.data || [])];
  if (data.length === 0) return [];

  return data.map((p: Record<string, unknown>) => {
    const proposerBot = p.bots as Record<string, string> | null;
    const expiresAt = new Date(p.expires_at as string);
    return {
      id: p.id as string,
      from_bot_id: p.proposer_id as string,
      from_display_name: proposerBot?.display_name || 'Unknown',
      type: p.type as string,
      message: p.message as string,
      building_id: p.building_id as string | null,
      expires_in_seconds: Math.max(0, Math.floor((expiresAt.getTime() - now.getTime()) / 1000)),
    };
  });
}

// ─── Artifact reactions helper ─────────────────────────

async function fetchArtifactReactions(
  botId: string,
  lastSeenAt: string | null,
  supabase: ReturnType<typeof createSupabaseClient>,
): Promise<{ artifact_id: string; type: string; title: string | null; reactor_name: string; reaction_type: string; comment: string | null; is_human: boolean }[]> {
  try {
    const since = lastSeenAt || new Date(Date.now() - 120_000).toISOString();

    // Fetch bot reactions (bot_id != self) and human reactions (reactor_user_id IS NOT NULL)
    // Use or() to include both: (bot_id is not self) OR (reactor_user_id is not null)
    const { data } = await supabase
      .from('artifact_reactions')
      .select('artifact_id, bot_id, reactor_user_id, reaction_type, comment, created_at, artifacts!inner(title, type, creator_bot_id), reactor:bots!artifact_reactions_bot_id_fkey(display_name)')
      .eq('artifacts.creator_bot_id', botId)
      .or(`bot_id.neq.${botId},reactor_user_id.not.is.null`)
      .gt('created_at', since)
      .order('created_at', { ascending: false })
      .limit(5);

    return (data || []).map((r: Record<string, unknown>) => {
      const art = r.artifacts as Record<string, unknown>;
      const reactor = r.reactor as Record<string, string> | null;
      const isHuman = !!(r.reactor_user_id);
      return {
        artifact_id: r.artifact_id as string,
        type: art?.type as string,
        title: art?.title as string | null,
        reactor_name: isHuman ? 'A human' : (reactor?.display_name || 'Someone'),
        reaction_type: r.reaction_type as string,
        comment: r.comment as string | null,
        is_human: isHuman,
      };
    });
  } catch (err) {
    captureError('[heartbeat] fetchArtifactReactions error', err, { fingerprint: ['heartbeat', 'fetchArtifactReactions'] });
    return [];
  }
}

// ─── Trending artifacts helper ─────────────────────────

async function fetchTrendingArtifacts(
  redis: RedisClient,
  supabase: ReturnType<typeof createSupabaseClient>,
): Promise<{ id: string; type: string; title: string | null; creator_name: string; creator_bot_id?: string }[]> {
  const cacheKey = 'trending_artifacts';
  try {
    const cached = await redis.get(cacheKey);
    if (cached) return JSON.parse(cached);

    const since = new Date(Date.now() - 24 * 60 * 60_000).toISOString();
    const { data: reactions } = await supabase
      .from('artifact_reactions')
      .select('artifact_id')
      .gt('created_at', since)
      .limit(5000);

    if (!reactions || reactions.length === 0) return [];

    const counts: Record<string, number> = {};
    for (const r of reactions) counts[r.artifact_id] = (counts[r.artifact_id] || 0) + 1;

    const topIds = Object.entries(counts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5)
      .map(([id]) => id);

    if (topIds.length === 0) return [];

    const { data: artifacts } = await supabase
      .from('artifacts')
      .select('id, type, title, creator_bot_id, created_at, creator:bots!artifacts_creator_bot_id_fkey(display_name)')
      .in('id', topIds);

    const result = (artifacts || []).map((a: Record<string, unknown>) => {
      const creator = a.creator as Record<string, string> | null;
      return {
        id: a.id as string,
        type: a.type as string,
        title: a.title as string | null,
        creator_name: creator?.display_name || 'Unknown',
        creator_bot_id: (a.creator_bot_id as string) || undefined,
      };
    }).sort((a, b) => (counts[b.id] || 0) - (counts[a.id] || 0));

    await redis.set(cacheKey, JSON.stringify(result), 300);
    return result;
  } catch (err) {
    captureError('[heartbeat] fetchTrendingArtifacts error', err, { fingerprint: ['heartbeat', 'fetchTrendingArtifacts'] });
    return [];
  }
}

// ─── Active quests helper ──────────────────────────────

interface ActiveQuest {
  id: string;
  title: string;
  description: string;
  type: string;
  building_type: string | null;
  requires_capability: string | null;
  theme: string | null;
  reward_rep: number;
  reward_badge: string | null;
  expires_at: string | null;
  predecessor_quest_id: string | null;
  chain_id: string | null;
  chain_step: number | null;
}

async function fetchAllActiveQuests(
  supabase: ReturnType<typeof createSupabaseClient>,
): Promise<ActiveQuest[]> {
  try {
    const now = new Date().toISOString();
    const { data } = await supabase
      .from('quests')
      .select('id, title, description, type, building_type, requires_capability, theme, reward_rep, reward_badge, expires_at, predecessor_quest_id, chain_id, chain_step')
      .eq('status', 'active')
      .or(`expires_at.is.null,expires_at.gt.${now}`)
      .limit(30);

    if (!data || data.length === 0) return [];

    return data.map(q => ({
      id: q.id,
      title: q.title,
      description: q.description,
      type: q.type,
      building_type: q.building_type,
      requires_capability: q.requires_capability,
      theme: q.theme,
      reward_rep: q.reward_rep,
      reward_badge: q.reward_badge,
      expires_at: q.expires_at,
      predecessor_quest_id: q.predecessor_quest_id || null,
      chain_id: q.chain_id ?? null,
      chain_step: q.chain_step ?? null,
    }));
  } catch (err) {
    captureError('[heartbeat] fetchAllActiveQuests error', err, { fingerprint: ['heartbeat', 'fetchAllActiveQuests'] });
    return [];
  }
}

/** Exclude completed quests, deterministic shuffle seeded by botId+date, pick 5 */
function personalizeQuests(quests: ActiveQuest[], completedIds: Set<string>, botId: string): ActiveQuest[] {
  const eligible = quests.filter(q => !completedIds.has(q.id));
  if (eligible.length <= 5) return eligible;

  // Deterministic seed: same agent sees same quests for the calendar day
  const today = new Date().toISOString().slice(0, 10);
  const seedStr = botId + today;
  let seed = 0;
  for (let i = 0; i < seedStr.length; i++) {
    seed = ((seed << 5) - seed + seedStr.charCodeAt(i)) | 0;
  }
  const seededRandom = () => {
    seed = (seed * 1664525 + 1013904223) & 0x7fffffff;
    return seed / 0x7fffffff;
  };

  // Seeded Fisher-Yates shuffle
  for (let i = eligible.length - 1; i > 0; i--) {
    const j = Math.floor(seededRandom() * (i + 1));
    [eligible[i], eligible[j]] = [eligible[j], eligible[i]];
  }
  return eligible.slice(0, 5);
}

// ─── Bot quest completions helper ──────────────────────

interface QuestCompletion {
  quest_id: string;
  quest_title: string;
  quest_type: string;
  chain_id: string | null;
  chain_step: number | null;
  submitted_at: string;
}

async function fetchBotQuestCompletions(
  supabase: ReturnType<typeof createSupabaseClient>,
  botId: string,
): Promise<QuestCompletion[]> {
  try {
    const { data } = await supabase
      .from('quest_submissions')
      .select('quest_id, submitted_at, quests:quest_id(title, type, chain_id, chain_step)')
      .eq('bot_id', botId)
      .order('submitted_at', { ascending: false })
      .limit(20);

    if (!data || data.length === 0) return [];

    return data.map(row => {
      const quest = row.quests as unknown as { title: string; type: string; chain_id: string | null; chain_step: number | null } | null;
      return {
        quest_id: row.quest_id as string,
        quest_title: quest?.title || 'Unknown',
        quest_type: quest?.type || 'unknown',
        chain_id: quest?.chain_id ?? null,
        chain_step: quest?.chain_step ?? null,
        submitted_at: row.submitted_at as string,
      };
    });
  } catch (err) {
    captureError('[heartbeat] fetchBotQuestCompletions error', err, { fingerprint: ['heartbeat', 'fetchBotQuestCompletions'] });
    return [];
  }
}

// ─── Relationships helper ──────────────────────────────

async function fetchRecentRelationships(
  botId: string,
  supabase: ReturnType<typeof createSupabaseClient>,
): Promise<{ recent: RelationshipSummary[]; new_today: RelationshipSummary[] }> {
  try {
    const { data } = await supabase
      .from('bot_relationships')
      .select('to_bot_id, type, last_interaction_at, interaction_count, first_encounter_at, bots!bot_relationships_to_bot_id_fkey(display_name)')
      .eq('from_bot_id', botId)
      .order('last_interaction_at', { ascending: false })
      .limit(10);

    if (!data || data.length === 0) return { recent: [], new_today: [] };

    const todayStart = new Date();
    todayStart.setHours(0, 0, 0, 0);
    const todayIso = todayStart.toISOString();
    const now = Date.now();

    const recent: RelationshipSummary[] = [];
    const newToday: RelationshipSummary[] = [];

    for (const r of data) {
      const bot = r.bots as { display_name?: string } | null;
      const name = bot?.display_name || 'Unknown';
      const lastMs = new Date(r.last_interaction_at as string).getTime();
      const diffMin = Math.floor((now - lastMs) / 60_000);
      const lastSeen = diffMin < 60 ? `${diffMin}m ago` : `${Math.floor(diffMin / 60)}h ago`;

      const entry: RelationshipSummary = {
        name,
        type: r.type as string,
        last_seen: lastSeen,
        interactions: r.interaction_count as number,
      };

      recent.push(entry);
      if ((r.first_encounter_at as string) >= todayIso) {
        newToday.push(entry);
      }
    }

    return { recent, new_today: newToday };
  } catch (err) {
    captureError('[heartbeat] fetchRecentRelationships error', err, { fingerprint: ['heartbeat', 'fetchRecentRelationships'] });
    return { recent: [], new_today: [] };
  }
}

