import { describe, it, expect } from 'vitest';

/**
 * Tests for the personalizeQuests deterministic shuffle logic.
 * The function is inlined in heartbeat.ts (not exported), so we replicate it here
 * to validate correctness of the seeded PRNG and Fisher-Yates shuffle.
 */

interface ActiveQuest {
  id: string;
  title: string;
  type: string;
  building_type: string | null;
  reward_rep: number;
}

function personalizeQuests(quests: ActiveQuest[], completedIds: Set<string>, botId: string): ActiveQuest[] {
  const eligible = quests.filter(q => !completedIds.has(q.id));
  if (eligible.length <= 5) return eligible;

  const today = new Date().toISOString().slice(0, 10);
  const seedStr = botId + today;
  let seed = 0;
  for (let i = 0; i < seedStr.length; i++) {
    seed = ((seed << 5) - seed + seedStr.charCodeAt(i)) | 0;
  }
  const seededRandom = () => {
    seed = (seed * 1664525 + 1013904223) & 0x7fffffff;
    return seed / 0x80000000;
  };

  for (let i = eligible.length - 1; i > 0; i--) {
    const j = Math.floor(seededRandom() * (i + 1));
    [eligible[i], eligible[j]] = [eligible[j], eligible[i]];
  }
  return eligible.slice(0, 5);
}

function makeQuests(count: number): ActiveQuest[] {
  return Array.from({ length: count }, (_, i) => ({
    id: `quest-${i}`,
    title: `Quest ${i}`,
    type: 'daily',
    building_type: null,
    reward_rep: 10,
  }));
}

describe('personalizeQuests — deterministic shuffle', () => {
  it('should return all quests when 5 or fewer eligible', () => {
    const quests = makeQuests(3);
    const result = personalizeQuests(quests, new Set(), 'bot-1');
    expect(result).toHaveLength(3);
    expect(result.map(q => q.id).sort()).toEqual(['quest-0', 'quest-1', 'quest-2']);
  });

  it('should return exactly 5 quests when more are eligible', () => {
    const quests = makeQuests(20);
    const result = personalizeQuests(quests, new Set(), 'bot-1');
    expect(result).toHaveLength(5);
  });

  it('should exclude completed quests', () => {
    const quests = makeQuests(10);
    const completed = new Set(['quest-0', 'quest-1', 'quest-2', 'quest-3', 'quest-4']);
    const result = personalizeQuests(quests, completed, 'bot-1');
    expect(result).toHaveLength(5);
    for (const q of result) {
      expect(completed.has(q.id)).toBe(false);
    }
  });

  it('should be deterministic — same bot+date = same quests', () => {
    const quests = makeQuests(50);
    const r1 = personalizeQuests(quests, new Set(), 'bot-abc');
    const r2 = personalizeQuests(quests, new Set(), 'bot-abc');
    expect(r1.map(q => q.id)).toEqual(r2.map(q => q.id));
  });

  it('should produce different quests for different bots', () => {
    const quests = makeQuests(50);
    const r1 = personalizeQuests(quests, new Set(), 'bot-abc');
    const r2 = personalizeQuests(quests, new Set(), 'bot-xyz');
    // With 50 quests choosing 5, probability of identical sets is negligible
    expect(r1.map(q => q.id)).not.toEqual(r2.map(q => q.id));
  });

  it('should never produce out-of-bounds indices (seededRandom always < 1.0)', () => {
    // Run with many different bot IDs to stress-test the PRNG
    const quests = makeQuests(77); // same count as production
    for (let i = 0; i < 100; i++) {
      const result = personalizeQuests(quests, new Set(), `stress-bot-${i}`);
      expect(result).toHaveLength(5);
      for (const q of result) {
        expect(q).toBeDefined();
        expect(q.id).toBeTruthy();
      }
    }
  });

  it('should not mutate the original quests array', () => {
    const quests = makeQuests(20);
    const originalIds = quests.map(q => q.id);
    personalizeQuests(quests, new Set(), 'bot-1');
    // filter() creates a new array, so original should be untouched
    expect(quests.map(q => q.id)).toEqual(originalIds);
  });

  it('should return empty when all quests are completed', () => {
    const quests = makeQuests(5);
    const completed = new Set(quests.map(q => q.id));
    const result = personalizeQuests(quests, completed, 'bot-1');
    expect(result).toHaveLength(0);
  });
});

